func NewSource(seed int64) Source {
	return newSource(seed)
}

func New(src Source) *Rand {
	s64, _ := src.(Source64)
	return &Rand{src: src, s64: s64}
}

func (r *Rand) Intn(n int) int {
	if n <= 0 {
		panic("invalid argument to Intn")
	}
	if n <= 1<<31-1 {
		return int(r.Int31n(int32(n)))
	}
	return int(r.Int63n(int64(n)))
}

func (r *Rand) Float64() float64 {
	// A clearer, simpler implementation would be:
	//	return float64(r.Int63n(1<<53)) / (1<<53)
	// However, Go 1 shipped with
	//	return float64(r.Int63()) / (1 << 63)
	// and we want to preserve that value stream.
	//
	// There is one bug in the value stream: r.Int63() may be so close
	// to 1<<63 that the division rounds up to 1.0, and we've guaranteed
	// that the result is always less than 1.0.
	//
	// We tried to fix this by mapping 1.0 back to 0.0, but since float64
	// values near 0 are much denser than near 1, mapping 1 to 0 caused
	// a theoretically significant overshoot in the probability of returning 0.
	// Instead of that, if we round up to 1, just try again.
	// Getting 1 only happens 1/2⁵³ of the time, so most clients
	// will not observe it anyway.
again:
	f := float64(r.Int63()) / (1 << 63)
	if f == 1 {
		goto again // resample; this branch is taken O(never)
	}
	return f
}

func Now() Time {
	sec, nsec, mono := runtimeNow()
	if mono == 0 {
		return Time{uint64(nsec), sec + unixToInternal, Local}
	}
	mono -= startNano
	sec += unixToInternal - minWall
	if uint64(sec)>>33 != 0 {
		// Seconds field overflowed the 33 bits available when
		// storing a monotonic time. This will be true after
		// March 16, 2157.
		return Time{uint64(nsec), sec + minWall, Local}
	}
	return Time{hasMonotonic | uint64(sec)<<nsecShift | uint64(nsec), mono, Local}
}

func (t Time) UnixNano() int64 {
	return (t.unixSec())*1e9 + int64(t.nsec())
}

howItsUsed.description:
### How It's Used

To use the `MockProvider` for generating random data, you can follow this example:

```go
package main

import (
	"fmt"
	"llm"
	"objectweaver/orchestration/jos/domain"
)

func main() {
	// Create a new instance of MockProvider
	provider := llm.NewMockProvider()

	// Define a generation configuration
	config := &domain.GenerationConfig{
		Definition: &jsonSchema.Definition{
			Type: jsonSchema.String, // Specify the type of data to generate
		},
	}

	// Generate random data
	result, metadata, err := provider.Generate("example prompt", config)
	if err != nil {
		fmt.Println("Error generating data:", err)
		return
	}

	// Output the generated result and metadata
	fmt.Println("Generated Data:", result)
	fmt.Println("Metadata:", metadata)
}
```

In this example, we import the necessary packages, create an instance of `MockProvider`, set up a `GenerationConfig`, and call the `Generate` method to produce random data based on the specified schema type. The generated data and metadata are then printed to the console.

### How It's Used

Suppose you are building an HTTP API endpoint for generating mock data for testing purposes. The `MockProvider` can be integrated into your handler to simulate responses without calling real APIs.

```go
// main.go
package main

import (
	"encoding/json"
	"net/http"
	"objectweaver/orchestration/jos/domain"
	"objectweaver/orchestration/jos/llm"
	"github.com/objectweaver/go-sdk/jsonSchema"
)

var mockProvider = llm.NewMockProvider()

func generateHandler(w http.ResponseWriter, r *http.Request) {
	// Parse request (assume JSON body with prompt and schema type)
	var req struct {
		Prompt    string                 `json:"prompt"`
		SchemaDef *jsonSchema.Definition `json:"schemaDef"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}

	config := &domain.GenerationConfig{Definition: req.SchemaDef}
	result, metadata, err := mockProvider.Generate(req.Prompt, config)
	if err != nil {
		http.Error(w, "generation error", http.StatusInternalServerError)
		return
	}

	resp := struct {
		Data     string                   `json:"data"`
		Metadata *domain.ProviderMetadata `json:"metadata"`
	}{
		Data:     result,
		Metadata: metadata,
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

func main() {
	http.HandleFunc("/generate", generateHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Flow of Data:**
1. The HTTP handler receives a request with a prompt and schema definition.
2. It calls `MockProvider.Generate`, passing the prompt and config.
3. The provider returns random mock data and metadata.
4. The handler encodes the result as JSON and sends it to the client.

This pattern can be adapted for gRPC services or business logic layers, allowing seamless integration of the mock provider for testing or benchmarking.

howToBreak.description:
### How to Break It

The `MockProvider` relies on a single instance of `rand.Rand` seeded with the current time for all random data generation. This architecture appears thread-safe because `rand.Rand` is not explicitly shared across goroutines. However, if the `MockProvider` instance is reused concurrently (e.g., in parallel unit tests or benchmarks), subtle race conditions can occur. The `rand.Rand` type is not safe for concurrent use: simultaneous calls to methods like `Intn`, `Float64`, or `Int63` can corrupt its internal state, leading to unpredictable results or panics.

A specific code modification that introduces this bug is to make `MockProvider` a singleton, shared across multiple goroutines:

```go
// Go
var globalProvider = NewMockProvider()

func main() {
    for i := 0; i < 10; i++ {
        go func() {
            globalProvider.Generate("prompt", &domain.GenerationConfig{Definition: &jsonSchema.Definition{Type: jsonSchema.String}})
        }()
    }
}
```

This change causes concurrent access to the same `rand.Rand` instance, triggering race conditions. The bug is subtle: tests may pass most of the time, but under heavy concurrency, failures or corrupted random output can occur. To avoid this, each goroutine should use its own `MockProvider` or synchronize access to the shared instance.

howToModify.description:
### How to Modify It

When modifying the `MockProvider` code, key areas requiring careful consideration include:

- **Random Data Generation Logic**: The `generateForType` method tightly couples schema types to random value generation. Extending support for new types or removing existing ones will require changes here.
- **Provider Metadata**: The `metadata` method returns hardcoded values. Adjusting metadata structure or adding new fields impacts both this method and any consumers of its output.
- **Randomness Source**: The provider uses a seeded `rand.Rand` instance. Changing how randomness is seeded or managed can affect reproducibility and thread safety.
- **Interface Compliance**: Methods like `SupportsStreaming` and `ModelType` are part of the provider interface. Removing or altering these may break compatibility with other components expecting these methods.

#### Refactoring Example: Extending Schema Type Support

To add support for nested arrays or custom types, refactor `generateForType` to handle recursive definitions:

```go
// Go
func (m *MockProvider) generateForType(def *jsonSchema.Definition) string {
    switch def.Type {
    case jsonSchema.Array:
        var items []string
        for i := 0; i < m.rng.Intn(5)+1; i++ {
            items = append(items, m.generateForType(def.Items))
        }
        return fmt.Sprintf("[%s]", strings.Join(items, ","))
    // ... existing cases
    }
}
```

**Implications:**

- **Performance**: Recursion or deeper nesting increases CPU and memory usage. Limit recursion depth to avoid stack overflows.
- **Security**: Generating large or deeply nested structures may expose denial-of-service risks if not bounded.
- **Maintainability**: Centralizing type handling logic improves extensibility but may require more rigorous testing as complexity grows.

When removing functionality (e.g., dropping support for a schema type), ensure all references and tests are updated to prevent runtime errors. For extending, document new behaviors and update interface contracts as needed.

howItsUsed.description:
### How It's Used

The `MockProvider` is typically integrated into a sophisticated system architecture to facilitate testing, benchmarking, or development workflows where real API calls are undesirable. Below is an example of how `MockProvider` can be used within a dependency injection container and as part of a message queue consumer in a microservices environment.

#### Example: Dependency Injection and Message Queue Consumer

Suppose you have a service that consumes generation requests from a Kafka topic. The service uses dependency injection to swap between real and mock providers based on environment configuration.

```go
// main.go
package main

import (
    "llm"
    "objectweaver/orchestration/jos/domain"
    "github.com/segmentio/kafka-go"
)

type GenerationService struct {
    provider llm.Provider // interface implemented by MockProvider
}

func (s *GenerationService) HandleMessage(msg kafka.Message) {
    // Deserialize request
    var req domain.GenerationConfig
    // ...unmarshal msg.Value into req...

    // Generate mock data
    result, metadata, err := s.provider.Generate("prompt", &req)
    if err != nil {
        // handle error
        return
    }
    // Process result, e.g., store or forward
}

// Dependency injection setup
func NewGenerationService(useMock bool) *GenerationService {
    var provider llm.Provider
    if useMock {
        provider = llm.NewMockProvider()
    } else {
        provider = llm.NewRealProvider() // hypothetical real provider
    }
    return &GenerationService{provider: provider}
}

func main() {
    service := NewGenerationService(true) // use mock for testing

    // Kafka consumer loop
    r := kafka.NewReader(kafka.ReaderConfig{...})
    for msg := range r.FetchMessage(context.Background()) {
        service.HandleMessage(msg)
    }
}
```

This pattern allows seamless switching between mock and real providers, enabling high-performance testing, CI/CD pipelines, and resource isolation without external dependencies. The `MockProvider` ensures deterministic, fast responses, ideal for load testing and integration scenarios.

