	case 1:
		w := &wrapError{msg: s}
		w.err, _ = a[p.wrappedErrs[0]].(error)
		err = w
	default:
		if p.reordered {
			slices.Sort(p.wrappedErrs)
		}
		var errs []error
		for i, argNum := range p.wrappedErrs {
			if i > 0 && p.wrappedErrs[i-1] == argNum {
				continue
			}
			if e, ok := a[argNum].(error); ok {
				errs = append(errs, e)
			}
		}
		err = &wrapErrors{s, errs}
	}
	p.free()
	return err
}

func Getenv(key string) string {
	testlog.Getenv(key)
	v, _ := syscall.Getenv(key)
	return v
}

func (f *File) Close() error {
	if f == nil {
		return ErrInvalid
	}
	return f.file.close()
}

func Remove(name string) error {
	// System call interface forces us to know
	// whether name is a file or directory.
	// Try both: it is cheaper on average than
	// doing a Stat plus the right one.
	e := ignoringEINTR(func() error {
		return syscall.Unlink(name)
	})
	if e == nil {
		return nil
	}
	e1 := ignoringEINTR(func() error {
		return syscall.Rmdir(name)
	})
	if e1 == nil {
		return nil
	}

	// Both failed: figure out which error to return.
	// OS X and Linux differ on whether unlink(dir)
	// returns EISDIR, so can't use that. However,
	// both agree that rmdir(file) returns ENOTDIR,
	// so we can use that to decide which error is real.
	// Rmdir might also return ENOTDIR if given a bad
	// file path, like /etc/passwd/foo, but in that case,
	// both errors will be ENOTDIR, so it's okay to
	// use the error from unlink.
	if e1 != syscall.ENOTDIR {
		e = e1
	}
	return &PathError{Op: "remove", Path: name, Err: e}
}

func CreateTemp(dir, pattern string) (*File, error) {
	if dir == "" {
		dir = TempDir()
	}

	prefix, suffix, err := prefixAndSuffix(pattern)
	if err != nil {
		return nil, &PathError{Op: "createtemp", Path: pattern, Err: err}
	}
	prefix = joinPath(dir, prefix)

	try := 0
	for {
		name := prefix + nextRandom() + suffix
		f, err := OpenFile(name, O_RDWR|O_CREATE|O_EXCL, 0600)
		if IsExist(err) {
			if try++; try < 10000 {
				continue
			}
			return nil, &PathError{Op: "createtemp", Path: prefix + "*" + suffix, Err: ErrExist}
		}
		return f, err
	}
}

func Atoi(s string) (int, error) {
	const fnAtoi = "Atoi"

	sLen := len(s)
	if intSize == 32 && (0 < sLen && sLen < 10) ||
		intSize == 64 && (0 < sLen && sLen < 19) {
		// Fast path for small integers that fit int type.
		s0 := s
		if s[0] == '-' || s[0] == '+' {
			s = s[1:]
			if len(s) < 1 {
				return 0, syntaxError(fnAtoi, s0)
			}
		}

		n := 0
		for _, ch := range []byte(s) {
			ch -= '0'
			if ch > 9 {
				return 0, syntaxError(fnAtoi, s0)
			}
			n = n*10 + int(ch)
		}
		if s0[0] == '-' {
			n = -n
		}
		return n, nil
	}

	// Slow path for invalid, big, or underscored integers.
	i64, err := ParseInt(s, 10, 0)
	if nerr, ok := err.(*NumError); ok {
		nerr.Func = fnAtoi
	}
	return int(i64), err
}

func (rw *RWMutex) RLock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.Disable()
	}
	if rw.readerCount.Add(1) < 0 {
		// A writer is pending, wait for it.
		runtime_SemacquireRWMutexR(&rw.readerSem, false, 0)
	}
	if race.Enabled {
		race.Enable()
		race.Acquire(unsafe.Pointer(&rw.readerSem))
	}
}

func (rw *RWMutex) RUnlock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.ReleaseMerge(unsafe.Pointer(&rw.writerSem))
		race.Disable()
	}
	if r := rw.readerCount.Add(-1); r < 0 {
		// Outlined slow-path to allow the fast-path to be inlined
		rw.rUnlockSlow(r)
	}
	if race.Enabled {
		race.Enable()
	}
}

func (rw *RWMutex) Lock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.Disable()
	}
	// First, resolve competition with other writers.
	rw.w.Lock()
	// Announce to readers there is a pending writer.
	r := rw.readerCount.Add(-rwmutexMaxReaders) + rwmutexMaxReaders
	// Wait for active readers.
	if r != 0 && rw.readerWait.Add(r) != 0 {
		runtime_SemacquireRWMutex(&rw.writerSem, false, 0)
	}
	if race.Enabled {
		race.Enable()
		race.Acquire(unsafe.Pointer(&rw.readerSem))
		race.Acquire(unsafe.Pointer(&rw.writerSem))
	}
}

func (rw *RWMutex) Unlock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.Release(unsafe.Pointer(&rw.readerSem))
		race.Disable()
	}

	// Announce to readers there is no active writer.
	r := rw.readerCount.Add(rwmutexMaxReaders)
	if r >= rwmutexMaxReaders {
		race.Enable()
		fatal("sync: Unlock of unlocked RWMutex")
	}
	// Unblock blocked readers, if any.
	for i := 0; i < int(r); i++ {
		runtime_Semrelease(&rw.readerSem, false, 0)
	}
	// Allow other writers to proceed.
	rw.w.Unlock()
	if race.Enabled {
		race.Enable()
	}
}

func (wg *WaitGroup) Add(delta int) {
	if race.Enabled {
		if delta < 0 {
			// Synchronize decrements with Wait.
			race.ReleaseMerge(unsafe.Pointer(wg))
		}
		race.Disable()
		defer race.Enable()
	}
	bubbled := false
	if synctest.IsInBubble() {
		// If Add is called from within a bubble, then all Add calls must be made
		// from the same bubble.
		switch synctest.Associate(wg) {
		case synctest.Unbubbled:
		case synctest.OtherBubble:
			// wg is already associated with a different bubble.
			fatal("sync: WaitGroup.Add called from multiple synctest bubbles")
		case synctest.CurrentBubble:
			bubbled = true
			state := wg.state.Or(waitGroupBubbleFlag)
			if state != 0 && state&waitGroupBubbleFlag == 0 {
				// Add has been called from outside this bubble.
				fatal("sync: WaitGroup.Add called from inside and outside synctest bubble")
			}
		}
	}
	state := wg.state.Add(uint64(delta) << 32)
	if state&waitGroupBubbleFlag != 0 && !bubbled {
		// Add has been called from within a synctest bubble (and we aren't in one).
		fatal("sync: WaitGroup.Add called from inside and outside synctest bubble")
	}
	v := int32(state >> 32)
	w := uint32(state & 0x7fffffff)
	if race.Enabled && delta > 0 && v == int32(delta) {
		// The first increment must be synchronized with Wait.
		// Need to model this as a read, because there can be
		// several concurrent wg.counter transitions from 0.
		race.Read(unsafe.Pointer(&wg.sema))
	}
	if v < 0 {
		panic("sync: negative WaitGroup counter")
	}
	if w != 0 && delta > 0 && v == int32(delta) {
		panic("sync: WaitGroup misuse: Add called concurrently with Wait")
	}
	if v > 0 || w == 0 {
		return
	}
	// This goroutine has set counter to 0 when waiters > 0.
	// Now there can't be concurrent mutations of state:
	// - Adds must not happen concurrently with Wait,
	// - Wait does not increment waiters if it sees counter == 0.
	// Still do a cheap sanity check to detect WaitGroup misuse.
	if wg.state.Load() != state {
		panic("sync: WaitGroup misuse: Add called concurrently with Wait")
	}
	// Reset waiters count to 0.
	wg.state.Store(0)
	if bubbled {
		// Adds must not happen concurrently with wait when counter is 0,
		// so we can safely disassociate wg from its current bubble.
		synctest.Disassociate(wg)
	}
	for ; w != 0; w-- {
		runtime_Semrelease(&wg.sema, false, 0)
	}
}

func (wg *WaitGroup) Done() {
	wg.Add(-1)
}

func (wg *WaitGroup) Wait() {
	if race.Enabled {
		race.Disable()
	}
	for {
		state := wg.state.Load()
		v := int32(state >> 32)
		w := uint32(state & 0x7fffffff)
		if v == 0 {
			// Counter is 0, no need to wait.
			if race.Enabled {
				race.Enable()
				race.Acquire(unsafe.Pointer(wg))
			}
			if w == 0 && state&waitGroupBubbleFlag != 0 && synctest.IsAssociated(wg) {
				// Adds must not happen concurrently with wait when counter is 0,
				// so we can disassociate wg from its current bubble.
				if wg.state.CompareAndSwap(state, 0) {
					synctest.Disassociate(wg)
				}
			}
			return
		}
		// Increment waiters count.
		if wg.state.CompareAndSwap(state, state+1) {
			if race.Enabled && w == 0 {
				// Wait must be synchronized with the first Add.
				// Need to model this is as a write to race with the read in Add.
				// As a consequence, can do the write only for the first waiter,
				// otherwise concurrent Waits will race with each other.
				race.Write(unsafe.Pointer(&wg.sema))
			}
			synctestDurable := false
			if state&waitGroupBubbleFlag != 0 && synctest.IsInBubble() {
				if race.Enabled {
					race.Enable()
				}
				if synctest.IsAssociated(wg) {
					// Add was called within the current bubble,
					// so this Wait is durably blocking.
					synctestDurable = true
				}
				if race.Enabled {
					race.Disable()
				}
			}
			runtime_SemacquireWaitGroup(&wg.sema, synctestDurable)
			if wg.state.Load() != 0 {
				panic("sync: WaitGroup is reused before previous Wait has returned")
			}
			if race.Enabled {
				race.Enable()
				race.Acquire(unsafe.Pointer(wg))
			}
			return
		}
	}
}

func NewTicker(d Duration) *Ticker {
	if d <= 0 {
		panic("non-positive interval for NewTicker")
	}
	// Give the channel a 1-element time buffer.
	// If the client falls behind while reading, we drop ticks
	// on the floor until the client catches up.
	c := make(chan Time, 1)
	t := (*Ticker)(unsafe.Pointer(newTimer(when(d), int64(d), sendTime, c, syncTimer(c))))
	t.C = c
	return t
}

func (t *Ticker) Stop() {
	if !t.initTicker {
		// This is misuse, and the same for time.Timer would panic,
		// but this didn't always panic, and we keep it not panicking
		// to avoid breaking old programs. See issue 21874.
		return
	}
	stopTimer((*Timer)(unsafe.Pointer(t)))
}

func (d Duration) Seconds() float64 {
	sec := d / Second
	nsec := d % Second
	return float64(sec) + float64(nsec)/1e9
}

func Now() Time {
	sec, nsec, mono := runtimeNow()
	if mono == 0 {
		return Time{uint64(nsec), sec + unixToInternal, Local}
	}
	mono -= startNano
	sec += unixToInternal - minWall
	if uint64(sec)>>33 != 0 {
		// Seconds field overflowed the 33 bits available when
		// storing a monotonic time. This will be true after
		// March 16, 2157.
		return Time{uint64(nsec), sec + minWall, Local}
	}
	return Time{hasMonotonic | uint64(sec)<<nsecShift | uint64(nsec), mono, Local}
}

func (t Time) Unix() int64 {
	return t.unixSec()
}

func (t Time) UnixNano() int64 {
	return (t.unixSec())*1e9 + int64(t.nsec())
}

func (c *BatchClient) UploadFile(ctx context.Context, filePath string) (*File, error) {
	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("failed to open file: %w", err)
	}
	defer file.Close()

	return c.UploadFileReader(ctx, file, filePath)
}

func (c *BatchClient) CreateBatch(ctx context.Context, req CreateBatchRequest) (*Batch, error) {
	resp, err := c.doRequest(ctx, "POST", "/batches", req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var batch Batch
	if err := json.NewDecoder(resp.Body).Decode(&batch); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	return &batch, nil
}

func (c *BatchClient) WaitForBatch(ctx context.Context, batchID string, pollIntervalOverride ...time.Duration) (*Batch, error) {
	interval := c.pollInterval
	if len(pollIntervalOverride) > 0 {
		interval = pollIntervalOverride[0]
	}

	ticker := time.NewTicker(interval)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return nil, ctx.Err()
		case <-ticker.C:
			batch, err := c.GetBatch(ctx, batchID)
			if err != nil {
				return nil, err
			}

			// Check for terminal states
			switch batch.Status {
			case StatusCompleted, StatusFailed, StatusExpired, StatusCancelled:
				return batch, nil
			}
		}
	}
}

func (c *BatchClient) ReadBatchResponses(ctx context.Context, fileID string) ([]BatchResponse, error) {
	content, err := c.GetFileContent(ctx, fileID)
	if err != nil {
		return nil, err
	}

	var responses []BatchResponse
	scanner := bufio.NewScanner(bytes.NewReader(content))
	for scanner.Scan() {
		var resp BatchResponse
		if err := json.Unmarshal(scanner.Bytes(), &resp); err != nil {
			return nil, fmt.Errorf("failed to parse response line: %w", err)
		}
		responses = append(responses, resp)
	}

	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("error reading responses: %w", err)
	}

	return responses, nil
}

func NewBatchWebhookNotifierFromEnv() IBatchWebhookNotifier {
	webhookURL := os.Getenv("LLM_BATCH_WEBHOOK_URL")
	apiKey := os.Getenv("LLM_BATCH_WEBHOOK_API_KEY")

	// If no webhook URL is configured, return a disabled notifier
	if webhookURL == "" {
		return &DefaultBatchWebhookNotifier{enabled: false}
	}

	config := &BatchWebhookConfig{
		WebhookURL:    webhookURL,
		APIKey:        apiKey,
		RetryAttempts: getIntFromEnvWithDefault("LLM_BATCH_WEBHOOK_RETRY_ATTEMPTS", 3),
		RetryDelay:    time.Duration(getIntFromEnvWithDefault("LLM_BATCH_WEBHOOK_RETRY_DELAY_SEC", 5)) * time.Second,
	}

	return NewBatchWebhookNotifier(config)
}

func NewModelConverter() ModelConverter {
	return &providerModelConverter{}
}

func NewDefaultOpenAIReqBuilder(modelConverter modelConverter.ModelConverter) RequestBuilder {
	return &defaultOpenAIReqBuilder{
		modelConverter: modelConverter,
	}
}

howItsUsed.description:
### How It's Used

```go
// Go

package main

import (
	"context"
	"fmt"
	"time"

	"objectweaver/llmManagement/client"
	"objectweaver/llmManagement/LLM"
)

// Example usage of DefaultBatchReqManager

func main() {
	// Set up the batch client (assume API keys/config are set via env)
	batchClient := client.NewBatchClientFromEnv()

	// Create the batch request manager
	batchManager, err := LLM.NewBatchReqManager(batchClient)
	if err != nil {
		panic(fmt.Sprintf("Failed to create batch manager: %v", err))
	}

	// Start the background flush routine
	batchManager.Start(context.Background())

	// Prepare a job to add
	job := &LLM.Job{
		Inputs: &LLM.Inputs{
			Prompt:       "What is the capital of France?",
			SystemPrompt: "You are a helpful assistant.",
			Model:        "gpt-3.5-turbo",
		},
		Result: make(chan any, 1),
		Error:  make(chan error, 1),
	}

	// Add the job to the batch manager
	if err := batchManager.AddJob(job); err != nil {
		fmt.Printf("Failed to add job: %v\n", err)
		return
	}

	// Optionally, force flush (send batch immediately)
	if err := batchManager.FlushBatch(context.Background()); err != nil {
		fmt.Printf("Flush error: %v\n", err)
	}

	// Wait for result or error
	select {
	case res := <-job.Result:
		fmt.Printf("Job result: %+v\n", res)
	case err := <-job.Error:
		fmt.Printf("Job error: %v\n", err)
	case <-time.After(30 * time.Second):
		fmt.Println("Timeout waiting for job result")
	}

	// Stop the batch manager gracefully
	if err := batchManager.Stop(context.Background()); err != nil {
		fmt.Printf("Error stopping batch manager: %v\n", err)
	}
}
```

This example demonstrates initializing the batch manager, adding a job, flushing the batch, and handling results/errors.

### How It's Used

Below is a realistic example of integrating the batch request manager into an HTTP handler within a Go web service. This demonstrates how jobs are queued for batch processing, how results are received asynchronously, and how the handler responds to the client.

```go
// main.go
package main

import (
	"context"
	"encoding/json"
	"net/http"
	"time"

	"objectweaver/llmManagement/LLM"
	"objectweaver/llmManagement/client"
)

var batchManager LLM.IBatchReqManager

func init() {
	batchClient := client.NewBatchClient("https://api.openai.com", "API_KEY")
	manager, err := LLM.NewBatchReqManager(batchClient)
	if err != nil {
		panic(err)
	}
	batchManager = manager
	batchManager.Start(context.Background())
}

func handleChatBatch(w http.ResponseWriter, r *http.Request) {
	var inputs LLM.Inputs
	if err := json.NewDecoder(r.Body).Decode(&inputs); err != nil {
		http.Error(w, "invalid input", http.StatusBadRequest)
		return
	}

	job := &LLM.Job{
		Inputs: &inputs,
		Result: make(chan *openai.ChatCompletionResponse, 1),
		Error:  make(chan error, 1),
	}

	if err := batchManager.AddJob(job); err != nil {
		http.Error(w, "failed to queue job", http.StatusInternalServerError)
		return
	}

	select {
	case resp := <-job.Result:
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(resp)
	case err := <-job.Error:
		http.Error(w, err.Error(), http.StatusInternalServerError)
	case <-time.After(30 * time.Second):
		http.Error(w, "timeout waiting for batch result", http.StatusGatewayTimeout)
	}
}

func main() {
	http.HandleFunc("/chat/batch", handleChatBatch)
	http.ListenAndServe(":8080", nil)
}
```

**Flow:**  
1. The HTTP handler receives a chat request and decodes the input.
2. A job is created and added to the batch manager.
3. The batch manager queues jobs and flushes them based on configured limits.
4. When batch processing completes, results are sent back to the job's channels.
5. The handler waits for the result or error and responds to the client.

howToBreak.description:
### How to Break It

The code uses a combination of mutexes (`sync.RWMutex`), channels, and goroutines to manage concurrent access and background processing. While the architecture is robust, subtle concurrency bugs can arise, especially around lock management and goroutine lifecycle.

**Potential Failure Points:**
- **Race Conditions:** The `AddJob` method unlocks the mutex before calling `FlushBatch`, then reacquires it. If another goroutine calls `AddJob` or `FlushBatch` in between, it could lead to inconsistent state or double-flushing.
- **Memory Leaks:** Goroutines started by `monitorBatchCompletion` are not tracked or cancelled, so if the context is never cancelled or batches hang, these goroutines may leak.
- **Deadlocks:** Improper use of `sync.WaitGroup` and mutexes could cause deadlocks, especially if `FlushBatch` blocks while holding the lock and another goroutine waits for it.
- **Security Vulnerabilities:** Temporary files for batch input are created but only removed after use. If the process crashes before `defer os.Remove(inputFile)` executes, sensitive data may remain on disk.

**Example Bug Introduction:**
Suppose you modify `AddJob` to hold the lock while calling `FlushBatch`:

```go
// BAD: Do not unlock before flushing
if newJobCount > m.maxRequestsPerBatch || newMemoryUsed > m.maxMemoryBytes {
    // Flush while holding the lock
    if err := m.FlushBatch(context.Background()); err != nil {
        return fmt.Errorf("failed to flush batch before adding job: %w", err)
    }
}
```

This change causes `FlushBatch` to attempt to acquire the same lock, resulting in a deadlock. The goroutine will block forever, preventing further job additions and batch processing. This subtle bug is hard to detect in testing but can halt production systems.

**Summary:**  
Concurrency bugs in lock management, goroutine cleanup, and resource handling are subtle but critical. Even small changes to lock acquisition order or goroutine lifecycle can break the system in ways that are difficult to debug.

