)

func main() {
	// Create a webhook notifier from environment variables
	notifier := LLM.NewBatchWebhookNotifierFromEnv()

	// Prepare dummy batch, responses, and jobs
	batch := &client.Batch{
		ID:           "batch123",
		Status:       client.BatchStatusCompleted,
		Metadata:     map[string]interface{}{"source": "test"},
		RequestCounts: client.RequestCounts{Total: 10, Success: 9, Failed: 1},
	}
	responses := []client.BatchResponse{
		{CustomID: "job1", Response: &client.Response{Body: map[string]interface{}{"result": "ok"}}, Error: nil},
		{CustomID: "job2", Error: &client.Error{Code: "ERR", Message: "Failed"}},
	}
	jobs := []*LLM.BatchJobEntry{
		{JobID: "job1"},
		{JobID: "job2"},
	}

	// Send batch completion notification
	err := notifier.NotifyBatchComplete(context.Background(), batch, responses, jobs)
	if err != nil {
		fmt.Printf("Notification failed: %v\n", err)
	} else {
		fmt.Println("Batch completion notification sent successfully.")
	}
}
```

This example demonstrates how to instantiate the batch webhook notifier, prepare the required batch and job data, and send a batch completion notification.

### How It's Used

Below is an example of integrating the `DefaultBatchWebhookNotifier` into a business logic service that processes batch jobs and sends a webhook notification upon completion. This demonstrates how the notifier is used in a typical application flow.

```go
// main.go
package main

import (
	"context"
	"log"
	"objectweaver/llmManagement/client"
	"objectweaver/llmManagement/LLM"
)

type BatchService struct {
	notifier LLM.IBatchWebhookNotifier
}

func NewBatchService() *BatchService {
	// Create notifier from environment variables
	notifier := LLM.NewBatchWebhookNotifierFromEnv()
	return &BatchService{notifier: notifier}
}

func (s *BatchService) ProcessBatch(ctx context.Context, batch *client.Batch, jobs []*LLM.BatchJobEntry) error {
	// ... business logic to process jobs ...
	responses := make([]client.BatchResponse, len(jobs))
	// Fill responses with results/errors

	// Notify webhook if enabled
	if s.notifier.IsEnabled() {
		err := s.notifier.NotifyBatchComplete(ctx, batch, responses, jobs)
		if err != nil {
			log.Printf("Failed to send batch webhook: %v", err)
			// Optionally handle error (e.g., retry, alert)
		}
	}
	return nil
}

func main() {
	ctx := context.Background()
	batch := &client.Batch{ID: "batch-123", Status: client.BatchStatusCompleted}
	jobs := []*LLM.BatchJobEntry{/* ... populate jobs ... */}

	service := NewBatchService()
	if err := service.ProcessBatch(ctx, batch, jobs); err != nil {
		log.Fatalf("Batch processing failed: %v", err)
	}
}
```

**Flow of Data:**
- The `BatchService` processes a batch and collects responses.
- After processing, it calls `NotifyBatchComplete` on the notifier.
- The notifier builds the payload and sends it to the configured webhook endpoint.
- Errors are logged and can be handled as needed.

