### How It's Used

```go
// main.go
package main

import (
	"fmt"
	"LLM"
)

// Assume Job and PriorityQueue are defined elsewhere in the LLM package

func main() {
	// Create a new RequestQueueManager
	queueManager := LLM.NewRequestQueueManager()

	// Create some jobs with priorities
	job1 := &LLM.Job{ID: 1, Priority: 2}
	job2 := &LLM.Job{ID: 2, Priority: 1}
	job3 := &LLM.Job{ID: 3, Priority: 3}

	// Enqueue jobs
	queueManager.Enqueue(job1)
	queueManager.Enqueue(job2)
	queueManager.Enqueue(job3)

