// Example implementation of ValidationPlugin
type MyValidationPlugin struct{}

func (p *MyValidationPlugin) Name() string { return "MyValidator" }
func (p *MyValidationPlugin) Version() string { return "1.0" }
func (p *MyValidationPlugin) Initialize(config map[string]interface{}) error { return nil }
