	ctx.ParentGen = "Account"

	// Set up a FieldTask (assume it's defined elsewhere)
	task := &domain.FieldTask{
		FieldType: "string",
		FieldName: "username",
	}

	// Optionally, set up GenerationHistory for retries
	history := &domain.GenerationHistory{
		attempts:   1,
		lastPrompt: "Generate a name for the user",
		lastResult: "john_doe",
	}

	// Create the PromptBuilder (from factory)
	promptBuilder := factory.CreatePromptBuilder()

	// Build a prompt without history
	prompt, err := promptBuilder.Build(task, ctx)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("Prompt:", prompt)

	// Build a prompt with history (for retries)
	promptWithHistory, err := promptBuilder.BuildWithHistory(task, ctx, history)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("Prompt with history:", promptWithHistory)
}
```
This example shows how to set up the context, task, and history, and call both `Build` and `BuildWithHistory` methods of a `PromptBuilder` implementation.

### How It's Used

Below is an example of integrating the `PromptBuilder` into an HTTP handler within a Go web service. This demonstrates how the prompt-building logic is used to generate context-aware prompts for an LLM field generation workflow.

```go
// main.go
package main

import (
	"encoding/json"
	"net/http"
	"yourapp/domain"
	"yourapp/infrastructure/prompt"
)

type GenerateFieldRequest struct {
	FieldName string   `json:"field_name"`
	ParentGen string   `json:"parent_gen"`
	SubLists  []string `json:"sub_lists"`
}

type GenerateFieldResponse struct {
	Prompt string `json:"prompt"`
}

func generateFieldHandler(w http.ResponseWriter, r *http.Request) {
	var req GenerateFieldRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}

	// Create context for prompt building
	ctx := domain.NewPromptContext()
	ctx.ParentGen = req.ParentGen
	ctx.ExistingSubLists = req.SubLists

	// Create a field task (details omitted for brevity)
	task := &domain.FieldTask{
		Name: req.FieldName,
	}

	// Use the default prompt builder
	builder := prompt.DefaultPromptBuilder{}

	// Build the prompt
	promptStr, err := builder.Build(task, ctx)
	if err != nil {
		http.Error(w, "failed to build prompt", http.StatusInternalServerError)
		return
	}

	// Return the generated prompt
	resp := GenerateFieldResponse{Prompt: promptStr}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}
```

**Flow:**  
1. The HTTP handler receives a request with field generation parameters.
2. It constructs a `PromptContext` using parent and sublist information.
3. A `FieldTask` is created for the requested field.
4. The handler invokes `PromptBuilder.Build` to generate a context-aware prompt.
5. The resulting prompt is returned to the client for further LLM processing.

### How It's Used

The `PromptBuilder` interface is typically integrated into a microservice architecture where prompt generation for LLMs is a core capability. For example, in a message queue system using Kafka, a consumer service receives field generation requests and leverages dependency injection to obtain a `PromptBuilder` implementation.

```go
// Go

type FieldGenerationConsumer struct {
    promptBuilder domain.PromptBuilder
}

func (c *FieldGenerationConsumer) HandleMessage(msg *KafkaMessage) {
    task := parseFieldTask(msg)
    ctx := domain.NewPromptContext()
    ctx.AddPrompt("Base context for generation")
    prompt, err := c.promptBuilder.Build(task, ctx)
    if err != nil {
        // Handle error, possibly retry with history
        history := &domain.GenerationHistory{attempts: 1}
        prompt, _ = c.promptBuilder.BuildWithHistory(task, ctx, history)
    }
    // Send prompt to LLM service, process result, publish outcome
}
```

In high-performance scenarios, such as batch processing with goroutine pools, the `PromptBuilder` is injected into worker routines. Each worker maintains its own `PromptContext` and `GenerationHistory`, ensuring thread-safe prompt construction and retry logic.

```go
// Go

func worker(id int, jobs <-chan *domain.FieldTask, builder domain.PromptBuilder) {
    for task := range jobs {
        ctx := domain.NewPromptContext()
        prompt, err := builder.Build(task, ctx)
        if err != nil {
            history := &domain.GenerationHistory{attempts: 1}
            prompt, _ = builder.BuildWithHistory(task, ctx, history)
        }
        // Use prompt for downstream LLM call
    }
}
```

This approach allows the prompt generation logic to be decoupled from transport and orchestration concerns, supporting scalability, testability, and robust error handling within the broader system infrastructure.

### How It's Used

```go
package main

import (
    "fmt"
    "github.com/objectweaver/go-sdk/jsonSchema"
    "yourapp/domain"
)

// Assume PrimitiveProcessor implements TypeProcessor
func main() {
    // Setup: create a processor and supporting objects
    processor := domain.NewPrimitiveProcessor() // hypothetical constructor
    schemaType := jsonSchema.StringType
    fieldTask := &domain.FieldTask{
        // fill in required fields
    }
    execContext := &domain.ExecutionContext{
        // fill in required fields
    }

    // Usage: check if processor can handle the type, then process
    if processor.CanProcess(schemaType) {
        result, err := processor.Process(fieldTask, execContext)
        if err != nil {
            fmt.Println("Error:", err)
            return
        }
        fmt.Println("Generated value:", result.Value)
    } else {
        fmt.Println("Processor cannot handle this schema type.")
    }
}
```

### How It's Used

Suppose you have an HTTP handler that generates structured JSON content using various schema types. The handler delegates processing to the appropriate `TypeProcessor` implementation based on the incoming request's schema type. Here’s how the integration might look:

```go
// Go

func GenerateContentHandler(w http.ResponseWriter, r *http.Request) {
    // Parse request to get schema type and input data
    var req GenerateContentRequest
    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        http.Error(w, "Invalid request", http.StatusBadRequest)
        return
    }

    // Create execution context and field task
    execCtx := &ExecutionContext{UserID: req.UserID}
    fieldTask := &FieldTask{
        SchemaType: req.SchemaType,
        Input:      req.Input,
    }

    // Get the appropriate TypeProcessor from the factory
    processor := generator_factory.CreateTypeProcessors()[req.SchemaType]
    if processor == nil || !processor.CanProcess(req.SchemaType) {
        http.Error(w, "Unsupported schema type", http.StatusBadRequest)
        return
    }

    // Process the task and handle the result
    result, err := processor.Process(fieldTask, execCtx)
    if err != nil {
        http.Error(w, "Processing error: "+err.Error(), http.StatusInternalServerError)
        return
    }

    // Return the generated value as JSON
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(result.Value)
}
```

**Flow of Data:**
1. The handler receives a request specifying a schema type.
2. It constructs a `FieldTask` and `ExecutionContext`.
3. It retrieves the correct `TypeProcessor` and checks if it can process the schema type.
4. The processor generates content using LLMProvider and validates the result.
5. The handler returns the generated value to the client.

This pattern allows seamless integration of schema-driven content generation into web services, business logic, or other application layers.

howToBreak.description:
### How to Break It

The architecture relies on interface-based polymorphism to route tasks to specialized processors based on JSON schema types. Each processor implements logic for handling its type, and the system depends on correct delegation and validation. Subtle failure points include:

- **Race Conditions:** If multiple goroutines invoke `ProcessStreaming` and share mutable state (e.g., within `ExecutionContext` or processor fields), unsynchronized access could corrupt data or cause inconsistent results.
- **Memory Leaks:** Streaming with channels (`<-chan *TokenStreamChunk`) risks leaks if consumers do not drain channels or if error paths leave goroutines running.
- **Security Vulnerabilities:** If LLM responses are parsed without strict validation, malicious input could trigger unsafe behavior or injection attacks.

#### Example Bug Introduction

Suppose you modify `ProcessStreaming` in a processor to spawn a goroutine that writes to a channel, but forget to close the channel on error or completion:

```go
func (p *SomeStreamingProcessor) ProcessStreaming(task *FieldTask, context *ExecutionContext) (<-chan *TokenStreamChunk, error) {
    ch := make(chan *TokenStreamChunk)
    go func() {
        for _, token := range tokens {
            ch <- token
        }
        // Missing: close(ch)
    }()
    return ch, nil
}
```

This omission causes consumers waiting on the channel to block indefinitely, leading to resource leaks and potential deadlocks. In a high-load scenario, this can exhaust goroutine and memory resources, degrading system stability.

