// Go

// Example: Integrating GenerationRequest and GenerationResult in an HTTP handler

import (
	"encoding/json"
	"net/http"
	"myapp/domain"
	"github.com/objectweaver/go-sdk/jsonSchema"
)

func generateHandler(w http.ResponseWriter, r *http.Request) {
	// Parse input
	var reqBody struct {
		Prompt string `json:"prompt"`
		Schema json.RawMessage `json:"schema"`
	}
	if err := json.NewDecoder(r.Body).Decode(&reqBody); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Convert schema to Definition
	schemaDef := &jsonSchema.Definition{}
	if err := json.Unmarshal(reqBody.Schema, schemaDef); err != nil {
		http.Error(w, "Invalid schema", http.StatusBadRequest)
		return
	}

	// Build GenerationRequest with custom metadata and constraints
	genReq := domain.NewGenerationRequest(reqBody.Prompt, schemaDef).
		WithMetadata("user_id", r.Header.Get("X-User-ID")).
		WithConstraints(&domain.Constraints{
			MaxRetries:     5,
			Timeout:        2 * time.Minute,
			MaxConcurrency: 5,
			VoteQuality:    90,
		})

	// Call business logic to generate result
	genResult := generateObject(genReq)

	// Prepare response
	resp := map[string]interface{}{
		"success": genResult.IsSuccess(),
		"data":    genResult.Data(),
		"metadata": genResult.Metadata(),
		"errors":  genResult.Errors(),
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

// Business logic using GenerationRequest and returning GenerationResult
func generateObject(req *domain.GenerationRequest) *domain.GenerationResult {
	// ... perform generation using req.Prompt(), req.Schema(), etc.
	// For illustration, return a dummy result
	data := map[string]interface{}{"field1": "value1"}
	metadata := domain.NewResultMetadata()
	metadata.ModelUsed = "gpt-4"
	return domain.NewGenerationResult(data, metadata)
}
```

This example shows how the core types are used to receive a request, build a `GenerationRequest` with custom options, invoke business logic, and return a structured `GenerationResult` in an HTTP API.

