func Now() Time {
	sec, nsec, mono := runtimeNow()
	if mono == 0 {
		return Time{uint64(nsec), sec + unixToInternal, Local}
	}
	mono -= startNano
	sec += unixToInternal - minWall
	if uint64(sec)>>33 != 0 {
		// Seconds field overflowed the 33 bits available when
		// storing a monotonic time. This will be true after
		// March 16, 2157.
		return Time{uint64(nsec), sec + minWall, Local}
	}
	return Time{hasMonotonic | uint64(sec)<<nsecShift | uint64(nsec), mono, Local}
}

howItsUsed.description:
### How It's Used

Below is a realistic example of how the streaming domain types are integrated into a gRPC service that streams incremental results to clients. The service receives data from an LLM provider, processes tokens, and sends structured streaming updates using `StreamChunk` and `TokenStreamChunk`.

```go
// main.go
package main

import (
	"context"
	"domain"
	pb "myapp/proto"
)

// LLMStreamService implements the gRPC streaming endpoint
type LLMStreamService struct {
	pb.UnimplementedLLMStreamServer
}

func (s *LLMStreamService) StreamTokens(req *pb.StreamRequest, stream pb.LLMStream_StreamTokensServer) error {
	progressive := domain.NewProgressiveValue(req.Key, []string{"root"})
	for {
		// Simulate receiving a token from an LLM provider
		tokenChunk := domain.NewTokenChunk("example_token")
		progressive.Append(tokenChunk.Token)

		// Wrap token in TokenStreamChunk
		tokenStream := domain.NewTokenStreamChunk(req.Key, tokenChunk.Token)
		tokenStream.Partial = progressive.CurrentValue()

		// Build StreamChunk for client
		streamChunk := domain.NewStreamChunk(req.Key, tokenStream)
		streamChunk.WithProgress(float64(len(progressive.Tokens())) / float64(req.ExpectedTokens))

		// Send to client
		if err := stream.Send(&pb.StreamResponse{
			Key:       streamChunk.Key,
			Value:     streamChunk.Value.(*domain.TokenStreamChunk).Partial,
			Progress:  streamChunk.Progress,
			IsFinal:   streamChunk.IsFinal,
			Timestamp: streamChunk.Timestamp.Unix(),
		}); err != nil {
			return err
		}

		// End condition
		if len(progressive.Tokens()) >= int(req.ExpectedTokens) {
			streamChunk.MarkFinal()
			break
		}
	}
	return nil
}
```

This example demonstrates how the domain streaming types are used to accumulate tokens, track progress, and send structured updates to clients in a gRPC streaming context.

### How It's Used

The streaming domain types are commonly integrated into event-driven architectures, such as a microservice consuming messages from a Kafka topic. For example, a service might process real-time data from an LLM (Large Language Model) and emit `StreamChunk` or `TokenStreamChunk` objects as events. These objects are then published to a message queue for downstream consumers.

```go
// Go: Kafka consumer using StreamChunk for progressive LLM output

func handleLLMStream(ctx context.Context, reader *kafka.Reader, writer *kafka.Writer) {
    for {
        msg, err := reader.ReadMessage(ctx)
        if err != nil {
            log.Fatal(err)
        }

        // Deserialize incoming message to TokenChunk
        var tokenChunk domain.TokenChunk
        json.Unmarshal(msg.Value, &tokenChunk)

        // Build progressive value
        pv := domain.NewProgressiveValue("response", []string{"root"})
        pv.Append(tokenChunk.Token)
        if tokenChunk.IsFinal {
            pv.MarkComplete()
        }

        // Wrap in AccumulatedStreamChunk for downstream consumers
        asc := &domain.AccumulatedStreamChunk{
            CurrentMap:        map[string]interface{}{"response": pv.CurrentValue()},
            ProgressiveFields: map[string]*domain.ProgressiveValue{"response": pv},
            NewToken:          domain.NewTokenStreamChunk("response", tokenChunk.Token),
            Progress:          computeProgress(tokenChunk),
            IsFinal:           tokenChunk.IsFinal,
        }

        // Publish to another topic for aggregation or UI streaming
        outMsg, _ := json.Marshal(asc)
        writer.WriteMessages(ctx, kafka.Message{Value: outMsg})
    }
}
```

This pattern enables high-throughput, low-latency streaming of incremental LLM results. The domain types support fine-grained control over streaming granularity and progressive accumulation, making them ideal for use in dependency injection containers, goroutine pools, or distributed systems where resource management and modularity are critical.

