func Errorf(format string, a ...any) error {
	p := newPrinter()
	p.wrapErrs = true
	p.doPrintf(format, a)
	s := string(p.buf)
	var err error
	switch len(p.wrappedErrs) {
	case 0:
		err = errors.New(s)
	case 1:
		w := &wrapError{msg: s}
		w.err, _ = a[p.wrappedErrs[0]].(error)
		err = w
	default:
		if p.reordered {
			slices.Sort(p.wrappedErrs)
		}
		var errs []error
		for i, argNum := range p.wrappedErrs {
			if i > 0 && p.wrappedErrs[i-1] == argNum {
				continue
			}
			if e, ok := a[argNum].(error); ok {
				errs = append(errs, e)
			}
		}
		err = &wrapErrors{s, errs}
	}
	p.free()
	return err
}

func NewPluginRegistry() *PluginRegistry {
	return &PluginRegistry{
		preProcessors:  make([]domain.PreProcessorPlugin, 0),
		postProcessors: make([]domain.PostProcessorPlugin, 0),
		validators:     make([]domain.ValidationPlugin, 0),
	}
}

func (r *PluginRegistry) ApplyPreProcessors(req *domain.GenerationRequest) (*domain.GenerationRequest, error) {
	result := req
	for _, processor := range r.preProcessors {
		var err error
		result, err = processor.PreProcess(result)
		if err != nil {
			return nil, err
		}
	}
	return result, nil
}

func NewExecutionContext(request *GenerationRequest) *ExecutionContext {
	return &ExecutionContext{
		request:          request,
		generatedValues:  make(map[string]interface{}),
		metadata:         make(map[string]interface{}),
		promptContext:    NewPromptContext(),
		generationConfig: DefaultGenerationConfig(),
	}
}

func NewGenerationResult(data map[string]interface{}, metadata *ResultMetadata) *GenerationResult {
	return &GenerationResult{
		data:     data,
		metadata: metadata,
		errors:   make([]error, 0),
	}
}

func NewResultMetadata() *ResultMetadata {
	return &ResultMetadata{
		TokensUsed: 0,
		Cost:       0.0,
		Duration:   0,
		ModelUsed:  "",
		FieldCount: 0,
	}
}

