func (rw *RWMutex) RLock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.Disable()
	}
	if rw.readerCount.Add(1) < 0 {
		// A writer is pending, wait for it.
		runtime_SemacquireRWMutexR(&rw.readerSem, false, 0)
	}
	if race.Enabled {
		race.Enable()
		race.Acquire(unsafe.Pointer(&rw.readerSem))
	}
}

func (rw *RWMutex) RUnlock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.ReleaseMerge(unsafe.Pointer(&rw.writerSem))
		race.Disable()
	}
	if r := rw.readerCount.Add(-1); r < 0 {
		// Outlined slow-path to allow the fast-path to be inlined
		rw.rUnlockSlow(r)
	}
	if race.Enabled {
		race.Enable()
	}
}

func (rw *RWMutex) Lock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.Disable()
	}
	// First, resolve competition with other writers.
	rw.w.Lock()
	// Announce to readers there is a pending writer.
	r := rw.readerCount.Add(-rwmutexMaxReaders) + rwmutexMaxReaders
	// Wait for active readers.
	if r != 0 && rw.readerWait.Add(r) != 0 {
		runtime_SemacquireRWMutex(&rw.writerSem, false, 0)
	}
	if race.Enabled {
		race.Enable()
		race.Acquire(unsafe.Pointer(&rw.readerSem))
		race.Acquire(unsafe.Pointer(&rw.writerSem))
	}
}

func (rw *RWMutex) Unlock() {
	if race.Enabled {
		race.Read(unsafe.Pointer(&rw.w))
		race.Release(unsafe.Pointer(&rw.readerSem))
		race.Disable()
	}

	// Announce to readers there is no active writer.
	r := rw.readerCount.Add(rwmutexMaxReaders)
	if r >= rwmutexMaxReaders {
		race.Enable()
		fatal("sync: Unlock of unlocked RWMutex")
	}
	// Unblock blocked readers, if any.
	for i := 0; i < int(r); i++ {
		runtime_Semrelease(&rw.readerSem, false, 0)
	}
	// Allow other writers to proceed.
	rw.w.Unlock()
	if race.Enabled {
		race.Enable()
	}
}

func NewTicker(d Duration) *Ticker {
	if d <= 0 {
		panic("non-positive interval for NewTicker")
	}
	// Give the channel a 1-element time buffer.
	// If the client falls behind while reading, we drop ticks
	// on the floor until the client catches up.
	c := make(chan Time, 1)
	t := (*Ticker)(unsafe.Pointer(newTimer(when(d), int64(d), sendTime, c, syncTimer(c))))
	t.C = c
	return t
}

func (t *Ticker) Stop() {
	if !t.initTicker {
		// This is misuse, and the same for time.Timer would panic,
		// but this didn't always panic, and we keep it not panicking
		// to avoid breaking old programs. See issue 21874.
		return
	}
	stopTimer((*Timer)(unsafe.Pointer(t)))
}

func Since(t Time) Duration {
	if t.wall&hasMonotonic != 0 && !runtimeIsBubbled() {
		// Common case optimization: if t has monotonic time, then Sub will use only it.
		return subMono(runtimeNano()-startNano, t.ext)
	}
	return Now().Sub(t)
}

func Now() Time {
	sec, nsec, mono := runtimeNow()
	if mono == 0 {
		return Time{uint64(nsec), sec + unixToInternal, Local}
	}
	mono -= startNano
	sec += unixToInternal - minWall
	if uint64(sec)>>33 != 0 {
		// Seconds field overflowed the 33 bits available when
		// storing a monotonic time. This will be true after
		// March 16, 2157.
		return Time{uint64(nsec), sec + minWall, Local}
	}
	return Time{hasMonotonic | uint64(sec)<<nsecShift | uint64(nsec), mono, Local}
}

func NewGenerationResult(data map[string]interface{}, metadata *ResultMetadata) *GenerationResult {
	return &GenerationResult{
		data:     data,
		metadata: metadata,
		errors:   make([]error, 0),
	}
}

func NewResultMetadata() *ResultMetadata {
	return &ResultMetadata{
		TokensUsed: 0,
		Cost:       0.0,
		Duration:   0,
		ModelUsed:  "",
		FieldCount: 0,
	}
}

func (m *ResultMetadata) AddCost(cost float64) {
	m.Cost += cost
}

func (m *ResultMetadata) AddTokens(tokens int) {
	m.TokensUsed += tokens
}

func (m *ResultMetadata) IncrementFieldCount() {
	m.FieldCount++
}

func NewStreamChunk(key string, value interface{}) *StreamChunk {
	return &StreamChunk{
		Key:       key,
		Value:     value,
		IsFinal:   false,
		Timestamp: time.Now(),
	}
}

func (s *StreamChunk) WithAccumulatedData(data map[string]interface{}) *StreamChunk {
	s.AccumulatedData = data
	return s
}

func (s *StreamChunk) WithProgress(progress float64) *StreamChunk {
	s.Progress = progress
	return s
}

func (s *StreamChunk) MarkFinal() *StreamChunk {
	s.IsFinal = true
	return s
}

func NewProgressiveValue(key string, path []string) *ProgressiveValue {
	return &ProgressiveValue{
		key:        key,
		path:       path,
		tokens:     make([]string, 0),
		isComplete: false,
	}
}

func (pv *ProgressiveValue) Append(token string) {
	pv.tokens = append(pv.tokens, token)
	pv.currentValue += token
}

func (pv *ProgressiveValue) CurrentValue() string {
	return pv.currentValue
}

func (pv *ProgressiveValue) IsComplete() bool {
	return pv.isComplete
}

func (pv *ProgressiveValue) MarkComplete() {
	pv.isComplete = true
}

