func Errorf(format string, a ...any) error {
	p := newPrinter()
	p.wrapErrs = true
	p.doPrintf(format, a)
	s := string(p.buf)
	var err error
	switch len(p.wrappedErrs) {
	case 0:
		err = errors.New(s)
	case 1:
		w := &wrapError{msg: s}
		w.err, _ = a[p.wrappedErrs[0]].(error)
		err = w
	default:
		if p.reordered {
			slices.Sort(p.wrappedErrs)
		}
		var errs []error
		for i, argNum := range p.wrappedErrs {
			if i > 0 && p.wrappedErrs[i-1] == argNum {
				continue
			}
			if e, ok := a[argNum].(error); ok {
				errs = append(errs, e)
			}
		}
		err = &wrapErrors{s, errs}
	}
	p.free()
	return err
}

func Printf(format string, a ...any) (n int, err error) {
	return Fprintf(os.Stdout, format, a...)
}

func Sscanf(str string, format string, a ...any) (n int, err error) {
	return Fscanf((*stringReader)(&str), format, a...)
}

func (p *PromptContext) AddPrompt(prompt string) {
	p.Prompts = append(p.Prompts, prompt)
}

func NewResultMetadata() *ResultMetadata {
	return &ResultMetadata{
		TokensUsed: 0,
		Cost:       0.0,
		Duration:   0,
		ModelUsed:  "",
		FieldCount: 0,
	}
}

func NewFieldTask(key string, definition *jsonSchema.Definition, parent *FieldTask) *FieldTask {
	path := []string{key}
	if parent != nil {
		path = append(parent.Path(), key)
	}

	return &FieldTask{
		id:           generateTaskID(key, path),
		key:          key,
		definition:   definition,
		parent:       parent,
		dependencies: make([]string, 0),
		path:         path,
		priority:     0,
	}
}

func NewTaskResult(taskID, key string, value interface{}, metadata *ResultMetadata) *TaskResult {
	return &TaskResult{
		taskID:   taskID,
		key:      key,
		value:    value,
		metadata: metadata,
		err:      nil,
	}
}

func (t *TaskResult) WithPath(path []string) *TaskResult {
	newResult := *t
