}

func NewSubmitterProvider(submitterType string) *SubmitterProvider {
    return &SubmitterProvider{
        Submitter: LLM.JobSubmitterFactory(submitterType),
    }
}

// Kafka consumer handler
func handleKafkaMessage(msg kafka.Message, provider *SubmitterProvider) {
    job := parseJob(msg.Value)
