}

func main() {
	llmProvider := &MockLLMProvider{}
	promptBuilder := &MockPromptBuilder{}
	processors := []domain.TypeProcessor{&MockTypeProcessor{}}

	executor := execution.NewCompositeTaskExecutor(llmProvider, promptBuilder, processors)

	// Setup a FieldTask and ExecutionContext
	definition := &jsonSchema.Definition{Type: jsonSchema.Integer}
	task := &domain.FieldTask{ /* fill required fields */ }
	context := &domain.ExecutionContext{ /* fill required fields */ }

	result, err := executor.Execute(task, context)
	if err != nil {
		fmt.Println("Error:", err)
		return
