		Voters:             protoDef.Voters,
		HashMap:            ConvertProtoToHashMap(protoDef.GetHashMap()),   // Check with Getters
		NarrowFocus:        ConvertProtoToFocus(protoDef.GetNarrowFocus()), // Handle nil safely
		Req:                ConvertProtoToRequestFormat(protoDef.GetReq()),
		Choices:            ConvertProtoToChoices(protoDef.GetChoices()),
		SpeechToText:       convertProtoSpeechToText(protoDef.GetSpeechToText()), // Safely handle nested structs
		TextToSpeech:       convertProtoTextToSpeech(protoDef.GetTextToSpeech()),
		SendImage:          convertProtoSendImage(protoDef.GetSendImage()), // Handle nil structs
		Stream:             protoDef.Stream,
	}

	// Handle Properties map
	if protoDef.Properties != nil {
		for key, protoProperty := range protoDef.Properties {
			modelDef.Properties[key] = *ConvertProtoToModel(protoProperty)
		}
	}

	return modelDef
}

func ConvertMapToStruct(m map[string]interface{}) (*structpb.Struct, error) {
	return structpb.NewStruct(m)
}

func CheckCircularDefinitions(def *jsonSchema.Definition) bool {
	visited := make(map[*jsonSchema.Definition]bool)
	recStack := make(map[*jsonSchema.Definition]bool)

	var dfs func(*jsonSchema.Definition) bool
	dfs = func(d *jsonSchema.Definition) bool {
		if d == nil {
			return false
		}
		// If the node is in the recursion stack, we found a cycle
		if recStack[d] {
			return true
		}
		// If the node is already visited and not part of the recursion stack
		if visited[d] {
			return false
		}

		// Mark the current node as visited and part of the recursion stack
		visited[d] = true
		recStack[d] = true

		// Recurse for all properties
		for _, prop := range d.Properties {
			if dfs(&prop) {
				return true
			}
		}

		// Recurse for items if present
		if d.Items != nil {
			if dfs(d.Items) {
				return true
			}
		}

		// Remove the node from the recursion stack
		recStack[d] = false
		return false
	}

	return dfs(def)
}

func NewGenerationRequest(prompt string, schema *jsonSchema.Definition) *GenerationRequest {
	return &GenerationRequest{
		prompt:      prompt,
		schema:      schema,
		context:     context.Background(),
		metadata:    make(map[string]interface{}),
		constraints: DefaultConstraints(),
	}
}

func (r *GenerationRequest) WithContext(ctx context.Context) *GenerationRequest {
	return &GenerationRequest{
		prompt:      r.prompt,
		schema:      r.schema,
		context:     ctx,
		metadata:    r.copyMetadata(),
		constraints: r.constraints,
	}
}

func (r *GenerationResult) IsSuccess() bool {
	return len(r.errors) == 0
}

func (r *GenerationResult) Data() map[string]interface{} {
	return r.data
}

func (r *GenerationResult) Metadata() *ResultMetadata {
	return r.metadata
}

func DefaultGeneratorConfig() *GeneratorConfig {
	return &GeneratorConfig{
		Mode:                ModeParallel,
		MaxConcurrency:      10,
		EnableCache:         false,
		EnableValidation:    true,
		EnableObservability: false,
		LLMProvider:         "openai",
		Plugins:             make([]domain.Plugin, 0),
		Granularity:         domain.GranularityField,
	}
}

func NewGeneratorFactory(config *GeneratorConfig) *GeneratorFactory {
	if config == nil {
		config = DefaultGeneratorConfig()
	}
	return &GeneratorFactory{config: config}
}

func (f *GeneratorFactory) Create() (domain.Generator, error) {
	// Create core components
	analyzer := f.createAnalyzer()
	executor := f.createExecutor()
	assembler := f.createAssembler()
	strategy := f.createStrategy()

	// Create generator based on mode
	var generator domain.Generator

	switch f.config.Mode {
	case ModeStreamingProgressive:
		generator = application.NewProgressiveGenerator(analyzer, executor, assembler.(domain.ProgressiveAssembler), strategy)
	case ModeStreaming, ModeStreamingComplete:
		generator = application.NewStreamingGenerator(analyzer, executor, assembler.(domain.StreamingAssembler), strategy)
	default:
		generator = application.NewDefaultGenerator(analyzer, executor, assembler, strategy)
	}

	// Register plugins if needed
	if pluggable, ok := generator.(PluginRegistry); ok {
		f.registerPlugins(pluggable)
	}

	return generator, nil
}

func (s *Server) createGeneratorConfig(schema *jsonSchema.Definition) *factory.GeneratorConfig {
	config := factory.DefaultGeneratorConfig()

	// Check if streaming is enabled
	if schema.Stream {
		// For non-streaming gRPC calls, we still use sync mode
		// Streaming is handled by StreamGeneratedObjectsV2
		config.Mode = factory.ModeSync
	} else {
		// Use dependency-aware mode for optimal execution
		config.Mode = factory.ModeDependencyAware
	}

	// Configure based on schema properties
	config.MaxConcurrency = 10
	config.EnableCache = true

	return config
}

func PrettyPrintJSON(jsonBytes []byte) {
	var jsonObj map[string]interface{}
	if err := json.Unmarshal(jsonBytes, &jsonObj); err != nil {
		log.Printf("Error unmarshalling JSON for pretty print: %v", err) // Use log.Printf, not Fatalf for a lib func
		return
	}
	prettyJSON, err := json.MarshalIndent(jsonObj, "", "    ")
	if err != nil {
		log.Printf("Error marshalling JSON for pretty print: %v", err)
		return
	}
	fmt.Println(string(prettyJSON))
}

