func As(err error, target any) bool {
	if err == nil {
		return false
	}
	if target == nil {
		panic("errors: target cannot be nil")
	}
	val := reflectlite.ValueOf(target)
	typ := val.Type()
	if typ.Kind() != reflectlite.Ptr || val.IsNil() {
		panic("errors: target must be a non-nil pointer")
	}
	targetType := typ.Elem()
	if targetType.Kind() != reflectlite.Interface && !targetType.Implements(errorType) {
		panic("errors: *target must be interface or implement error")
	}
	return as(err, target, val, targetType)
}

func Printf(format string, v ...any) {
	std.output(0, 2, func(b []byte) []byte {
		return fmt.Appendf(b, format, v...)
	})
}

func (wg *WaitGroup) Add(delta int) {
	if race.Enabled {
		if delta < 0 {
			// Synchronize decrements with Wait.
			race.ReleaseMerge(unsafe.Pointer(wg))
		}
		race.Disable()
		defer race.Enable()
	}
	bubbled := false
	if synctest.IsInBubble() {
		// If Add is called from within a bubble, then all Add calls must be made
		// from the same bubble.
		switch synctest.Associate(wg) {
		case synctest.Unbubbled:
		case synctest.OtherBubble:
			// wg is already associated with a different bubble.
			fatal("sync: WaitGroup.Add called from multiple synctest bubbles")
		case synctest.CurrentBubble:
			bubbled = true
			state := wg.state.Or(waitGroupBubbleFlag)
			if state != 0 && state&waitGroupBubbleFlag == 0 {
				// Add has been called from outside this bubble.
				fatal("sync: WaitGroup.Add called from inside and outside synctest bubble")
			}
		}
	}
	state := wg.state.Add(uint64(delta) << 32)
	if state&waitGroupBubbleFlag != 0 && !bubbled {
		// Add has been called from within a synctest bubble (and we aren't in one).
		fatal("sync: WaitGroup.Add called from inside and outside synctest bubble")
	}
	v := int32(state >> 32)
	w := uint32(state & 0x7fffffff)
	if race.Enabled && delta > 0 && v == int32(delta) {
		// The first increment must be synchronized with Wait.
		// Need to model this as a read, because there can be
		// several concurrent wg.counter transitions from 0.
		race.Read(unsafe.Pointer(&wg.sema))
	}
	if v < 0 {
		panic("sync: negative WaitGroup counter")
	}
	if w != 0 && delta > 0 && v == int32(delta) {
		panic("sync: WaitGroup misuse: Add called concurrently with Wait")
	}
	if v > 0 || w == 0 {
		return
	}
	// This goroutine has set counter to 0 when waiters > 0.
	// Now there can't be concurrent mutations of state:
	// - Adds must not happen concurrently with Wait,
	// - Wait does not increment waiters if it sees counter == 0.
	// Still do a cheap sanity check to detect WaitGroup misuse.
	if wg.state.Load() != state {
		panic("sync: WaitGroup misuse: Add called concurrently with Wait")
	}
	// Reset waiters count to 0.
	wg.state.Store(0)
	if bubbled {
		// Adds must not happen concurrently with wait when counter is 0,
		// so we can safely disassociate wg from its current bubble.
		synctest.Disassociate(wg)
	}
	for ; w != 0; w-- {
		runtime_Semrelease(&wg.sema, false, 0)
	}
}

func (wg *WaitGroup) Done() {
	wg.Add(-1)
}

func (wg *WaitGroup) Wait() {
	if race.Enabled {
		race.Disable()
	}
	for {
		state := wg.state.Load()
		v := int32(state >> 32)
		w := uint32(state & 0x7fffffff)
		if v == 0 {
			// Counter is 0, no need to wait.
			if race.Enabled {
				race.Enable()
				race.Acquire(unsafe.Pointer(wg))
			}
			if w == 0 && state&waitGroupBubbleFlag != 0 && synctest.IsAssociated(wg) {
				// Adds must not happen concurrently with wait when counter is 0,
				// so we can disassociate wg from its current bubble.
				if wg.state.CompareAndSwap(state, 0) {
					synctest.Disassociate(wg)
				}
			}
			return
		}
		// Increment waiters count.
		if wg.state.CompareAndSwap(state, state+1) {
			if race.Enabled && w == 0 {
				// Wait must be synchronized with the first Add.
				// Need to model this is as a write to race with the read in Add.
				// As a consequence, can do the write only for the first waiter,
				// otherwise concurrent Waits will race with each other.
				race.Write(unsafe.Pointer(&wg.sema))
			}
			synctestDurable := false
			if state&waitGroupBubbleFlag != 0 && synctest.IsInBubble() {
				if race.Enabled {
					race.Enable()
				}
				if synctest.IsAssociated(wg) {
					// Add was called within the current bubble,
					// so this Wait is durably blocking.
					synctestDurable = true
				}
				if race.Enabled {
					race.Disable()
				}
			}
			runtime_SemacquireWaitGroup(&wg.sema, synctestDurable)
			if wg.state.Load() != 0 {
				panic("sync: WaitGroup is reused before previous Wait has returned")
			}
			if race.Enabled {
				race.Enable()
				race.Acquire(unsafe.Pointer(wg))
			}
			return
		}
	}
}

func (lim *Limiter) Burst() int {
	lim.mu.Lock()
	defer lim.mu.Unlock()
	return lim.burst
}

func NewLimiter(r Limit, b int) *Limiter {
	return &Limiter{
		limit:  r,
		burst:  b,
		tokens: float64(b),
	}
}

func (lim *Limiter) Wait(ctx context.Context) (err error) {
	return lim.WaitN(ctx, 1)
}

func (lim *Limiter) WaitN(ctx context.Context, n int) (err error) {
	// The test code calls lim.wait with a fake timer generator.
	// This is the real timer generator.
	newTimer := func(d time.Duration) (<-chan time.Time, func() bool, func()) {
		timer := time.NewTimer(d)
		return timer.C, timer.Stop, func() {}
	}

	return lim.wait(ctx, n, time.Now(), newTimer)
}

func (ec *ErrorClassifier) Classify(err error) ErrorType {
	if err == nil {
		return -1
	}

	logger.Output.Println(fmt.Sprintf("ErrorClassifier: Classifying error: %v", err))

	if errors.Is(err, io.EOF) {
		return ErrorTypeTransient
	}

	var rateLimitErr *RateLimitError
	if errors.As(err, &rateLimitErr) || strings.Contains(err.Error(), "429") {
		return ErrorTypeRateLimit
	}

	errStr := err.Error()

	// Handle OpenAI-specific error types
	if strings.Contains(errStr, "OpenAI API error") {
		if strings.Contains(errStr, "[type: invalid_request_error]") {
			return ErrorTypePermanent // Invalid requests shouldn't be retried
		}
		if strings.Contains(errStr, "[type: rate_limit_exceeded]") {
			return ErrorTypeRateLimit
		}
		if strings.Contains(errStr, "[type: server_error]") || strings.Contains(errStr, "[type: service_unavailable]") {
			return ErrorTypeTransient // Server errors can be retried
		}
	}

	transientErrors := []string{
		"client connection lost",
		"Service Unavailable",
		"Internal Server Error",
		"context deadline exceeded",
		"connection reset by peer",
		"broken pipe",
		"unexpected EOF",                                       // Added this error to the list
		"HTTP request failed with status 429",                  // Rate limit
		"HTTP request failed with status 502",                  // Bad Gateway
		"HTTP request failed with status 503",                  // Service Unavailable
		"HTTP request failed with status 504",                  // Gateway Timeout
		"failed to unmarshal json into ChatCompletionResponse", // JSON parsing errors (often due to error responses)
	}
	for _, te := range transientErrors {
		if strings.Contains(errStr, te) {
			return ErrorTypeTransient
		}
	}

	// Check for specific HTTP error codes that should be permanent
	permanentHttpErrors := []string{
		"HTTP request failed with status 401", // Unauthorized
		"HTTP request failed with status 403", // Forbidden
		"HTTP request failed with status 404", // Not Found
		"HTTP request failed with status 400", // Bad Request
	}
	for _, pe := range permanentHttpErrors {
		if strings.Contains(errStr, pe) {
			return ErrorTypePermanent
		}
	}

	return ErrorTypePermanent
}

func (q *JobQueue) Enqueue(job *Job) {
	q.mu.Lock()
	defer q.mu.Unlock()
	q.fifo = append(q.fifo, job)
}

func (q *JobQueue) Prepend(job *Job) {
	q.mu.Lock()
	defer q.mu.Unlock()
	q.fifo = append([]*Job{job}, q.fifo...)
}

func (q *JobQueue) StartManager(wg *sync.WaitGroup) {
	defer wg.Done()
	for {
		select {
		case <-q.stopChan:
			close(q.jobChan)
			return
		default:
			if job := q.dequeue(); job != nil {
				q.jobChan <- job
			} else {
				time.Sleep(10 * time.Millisecond) // Wait if queue is empty
			}
		}
	}
}

func (q *JobQueue) StopManager() {
	close(q.stopChan)
}

func (q *JobQueue) Jobs() <-chan *Job {
	return q.jobChan
}

func (rh *RetryHandler) HandleTransientError(job *Job, queue *JobQueue, workerID int, err error) {
	if job.Retries < rh.MaxTransientRetries {
		job.Retries++
		if rh.Verbose {
			logger.Output.Println(fmt.Sprintf("WARN: Transient error, retrying (%d/%d). Worker: %d, Error: %v", job.Retries, rh.MaxTransientRetries, workerID, err))
		}
		// Apply a simple incremental delay before requeueing
		time.Sleep(100 * time.Millisecond * time.Duration(job.Retries))
		queue.Prepend(job)
	} else {
		logger.Output.Println(fmt.Sprintf("ERROR: Job failed after max retries for transient error. Worker: %d, Error: %v", workerID, err))
		job.Result <- nil
	}
}

func (rh *RetryHandler) HandlePermanentError(job *Job, workerID int, err error) {
	logger.Output.Println(fmt.Sprintf("ERROR: Permanent error, dropping job. Worker: %d, Error: %v", workerID, err))
	job.Result <- nil
}

