func ConvertProtoToModel(protoDef *pb.Definition) *jsonSchema.Definition {
	if protoDef == nil {
		return nil
	}

	modelDef := &jsonSchema.Definition{
		Type:               jsonSchema.DataType(protoDef.Type),
		Instruction:        protoDef.Instruction,
		Properties:         make(map[string]jsonSchema.Definition),
		Items:              ConvertProtoToModel(protoDef.GetItems()), // Use Getters to handle nil cases
		Model:              string(protoDef.Model),
		ProcessingOrder:    protoDef.ProcessingOrder,
		SystemPrompt:       getStringPointer(protoDef.GetSystemPrompt()), // Safe getter for pointers
		ImprovementProcess: protoDef.ImprovementProcess,
		SelectFields:       protoDef.SelectFields,
		Voters:             protoDef.Voters,
		HashMap:            ConvertProtoToHashMap(protoDef.GetHashMap()),   // Check with Getters
		NarrowFocus:        ConvertProtoToFocus(protoDef.GetNarrowFocus()), // Handle nil safely
		Req:                ConvertProtoToRequestFormat(protoDef.GetReq()),
		Choices:            ConvertProtoToChoices(protoDef.GetChoices()),
		SpeechToText:       convertProtoSpeechToText(protoDef.GetSpeechToText()), // Safely handle nested structs
		TextToSpeech:       convertProtoTextToSpeech(protoDef.GetTextToSpeech()),
		SendImage:          convertProtoSendImage(protoDef.GetSendImage()), // Handle nil structs
		Stream:             protoDef.Stream,
	}

	// Handle Properties map
	if protoDef.Properties != nil {
		for key, protoProperty := range protoDef.Properties {
			modelDef.Properties[key] = *ConvertProtoToModel(protoProperty)
		}
	}

	return modelDef
}

func NewStruct(v map[string]any) (*Struct, error) {
	x := &Struct{Fields: make(map[string]*Value, len(v))}
	for k, v := range v {
		if !utf8.ValidString(k) {
			return nil, protoimpl.X.NewError("invalid UTF-8 in string: %q", k)
		}
		var err error
		x.Fields[k], err = NewValue(v)
		if err != nil {
			return nil, err
		}
	}
	return x, nil
}

func CheckCircularDefinitions(def *jsonSchema.Definition) bool {
	visited := make(map[*jsonSchema.Definition]bool)
	recStack := make(map[*jsonSchema.Definition]bool)

	var dfs func(*jsonSchema.Definition) bool
	dfs = func(d *jsonSchema.Definition) bool {
		if d == nil {
			return false
		}
		// If the node is in the recursion stack, we found a cycle
		if recStack[d] {
			return true
		}
		// If the node is already visited and not part of the recursion stack
		if visited[d] {
			return false
		}

		// Mark the current node as visited and part of the recursion stack
		visited[d] = true
		recStack[d] = true

		// Recurse for all properties
		for _, prop := range d.Properties {
			if dfs(&prop) {
				return true
			}
		}

		// Recurse for items if present
		if d.Items != nil {
			if dfs(d.Items) {
				return true
			}
		}

		// Remove the node from the recursion stack
		recStack[d] = false
		return false
	}

	return dfs(def)
}

func NewGenerationRequest(prompt string, schema *jsonSchema.Definition) *GenerationRequest {
	return &GenerationRequest{
		prompt:      prompt,
		schema:      schema,
		context:     context.Background(),
		metadata:    make(map[string]interface{}),
		constraints: DefaultConstraints(),
	}
}

func (r *GenerationRequest) WithContext(ctx context.Context) *GenerationRequest {
	return &GenerationRequest{
		prompt:      r.prompt,
		schema:      r.schema,
		context:     ctx,
		metadata:    r.copyMetadata(),
		constraints: r.constraints,
	}
}

func DefaultGeneratorConfig() *GeneratorConfig {
	return &GeneratorConfig{
		Mode:                ModeParallel,
		MaxConcurrency:      10,
		EnableCache:         false,
		EnableValidation:    true,
		EnableObservability: false,
		LLMProvider:         "openai",
		Plugins:             make([]domain.Plugin, 0),
		Granularity:         domain.GranularityField,
	}
}

func NewGeneratorFactory(config *GeneratorConfig) *GeneratorFactory {
	if config == nil {
		config = DefaultGeneratorConfig()
	}
	return &GeneratorFactory{config: config}
}

func (f *GeneratorFactory) Create() (domain.Generator, error) {
	// Create core components
	analyzer := f.createAnalyzer()
	executor := f.createExecutor()
	assembler := f.createAssembler()
	strategy := f.createStrategy()

	// Create generator based on mode
	var generator domain.Generator

	switch f.config.Mode {
	case ModeStreamingProgressive:
		generator = application.NewProgressiveGenerator(analyzer, executor, assembler.(domain.ProgressiveAssembler), strategy)
	case ModeStreaming, ModeStreamingComplete:
		generator = application.NewStreamingGenerator(analyzer, executor, assembler.(domain.StreamingAssembler), strategy)
	default:
		generator = application.NewDefaultGenerator(analyzer, executor, assembler, strategy)
	}

	// Register plugins if needed
	if pluggable, ok := generator.(PluginRegistry); ok {
		f.registerPlugins(pluggable)
	}

	return generator, nil
}

func (s *Server) streamComplete(generator domain.Generator, request *domain.GenerationRequest, stream pb.JSONSchemaService_StreamGeneratedObjectsServer) error {
	// Get the streaming channel
	streamChan, err := generator.GenerateStream(request)
	if err != nil {
		log.Printf("Failed to start streaming generation: %v", err)
		return err
	}

	accumulatedData := make(map[string]interface{})
	totalCost := 0.0

	// Process each chunk
	for chunk := range streamChan {
		if chunk == nil {
			continue
		}

		// Update accumulated data with new field
		if chunk.Key != "" && chunk.Value != nil {
			accumulatedData[chunk.Key] = chunk.Value
		}

		// Use AccumulatedData if provided (for complete streaming mode)
		// Note: StreamChunk doesn't have AccumulatedData, we build it ourselves

		// Convert accumulated data to protobuf struct
		protoStruct, err := structpb.NewStruct(accumulatedData)
		if err != nil {
			log.Printf("Failed to convert map to protobuf struct: %v", err)
			return err
		}

		// Create streaming response
		response := &pb.StreamingResponse{
			Data:    protoStruct,
			UsdCost: totalCost,
			Status:  "Processing",
		}

		// Send the chunk
		if err := stream.Send(response); err != nil {
			log.Printf("Failed to send streaming response: %v", err)
			return err
		}

		// Track if this is the final chunk
		if chunk.IsFinal {
			break
		}
	}

	// Send final completion message
	finalStruct, err := structpb.NewStruct(accumulatedData)
	if err != nil {
		log.Printf("Failed to create final struct: %v", err)
		return err
	}

	finalResponse := &pb.StreamingResponse{
		Data:    finalStruct,
		UsdCost: totalCost,
		Status:  "Completed",
	}

	if err := stream.Send(finalResponse); err != nil {
		log.Printf("Failed to send final response: %v", err)
		return err
	}

	return nil
}

func (s *Server) streamProgressively(generator domain.Generator, request *domain.GenerationRequest, stream pb.JSONSchemaService_StreamGeneratedObjectsServer) error {
	// Get the progressive streaming channel
	progressiveChan, err := generator.GenerateStreamProgressive(request)
	if err != nil {
		log.Printf("Failed to start progressive streaming: %v", err)
		return err
	}

	accumulatedData := make(map[string]interface{})
	totalCost := 0.0

	// Process each progressive chunk (token-level)
	for chunk := range progressiveChan {
		if chunk == nil {
			continue
		}

		// Update accumulated data with new token
		if chunk.NewToken != nil {
			if chunk.NewToken.Complete {
				// Token stream complete for this field, store final value
				accumulatedData[chunk.NewToken.Key] = chunk.NewToken.Partial
			} else {
				// Store partial value
				accumulatedData[chunk.NewToken.Key] = chunk.NewToken.Partial
			}
		}

		// Use CurrentMap if provided
		if chunk.CurrentMap != nil {
			accumulatedData = chunk.CurrentMap
		}

		// Convert to protobuf struct
		protoStruct, err := structpb.NewStruct(accumulatedData)
		if err != nil {
			// Log but don't fail - might be due to incomplete data
			log.Printf("Warning: Failed to convert partial data to struct: %v", err)
			continue
		}

		// Create streaming response
		response := &pb.StreamingResponse{
			Data:    protoStruct,
			UsdCost: totalCost,
			Status:  "Processing",
		}

		// Send the progressive update
		if err := stream.Send(response); err != nil {
			log.Printf("Failed to send progressive response: %v", err)
			return err
		}

		// Check if complete
		if chunk.IsFinal {
			break
		}
	}

	// Send final completion message
	finalStruct, err := structpb.NewStruct(accumulatedData)
	if err != nil {
		log.Printf("Failed to create final struct: %v", err)
		return err
	}

	finalResponse := &pb.StreamingResponse{
		Data:    finalStruct,
		UsdCost: totalCost,
		Status:  "Completed",
	}

	if err := stream.Send(finalResponse); err != nil {
		log.Printf("Failed to send final response: %v", err)
		return err
	}

	return nil
}

func (s *Server) createStreamingConfig(schema *jsonSchema.Definition) *factory.GeneratorConfig {
	config := factory.DefaultGeneratorConfig()

	// Determine streaming granularity
	if s.shouldUseProgressiveStreaming(schema) {
		// Token-level streaming (most granular)
		config.Mode = factory.ModeStreamingProgressive
		config.Granularity = domain.GranularityToken
	} else {
		// Complete streaming (field-level with accumulated state)
		config.Mode = factory.ModeStreamingComplete
		config.Granularity = domain.GranularityField
	}

	// Configure based on schema properties
	config.MaxConcurrency = 10
	config.EnableCache = false // Disable cache for streaming

	return config
}

func (s *Server) shouldUseProgressiveStreaming(schema *jsonSchema.Definition) bool {
	// Check if any nested field has Stream enabled
	if schema.Properties != nil {
		for _, prop := range schema.Properties {
			if prop.Stream {
				return true // Use progressive streaming for token updates
			}
		}
	}

	// Default to field-level streaming
	return false
}

