)

// Server implements the JSONSchemaServiceServer interface
type Server struct {
	pb.UnimplementedJSONSchemaServiceServer
	grpcService.Server // Embed core streaming logic
}

func main() {
	lis, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatalf("failed to listen: %v", err)
	}
	s := grpc.NewServer()
	pb.RegisterJSONSchemaServiceServer(s, &Server{})
	log.Println("gRPC server listening on :50051")
	if err := s.Serve(lis); err != nil {
		log.Fatalf("failed to serve: %v", err)
	}
}

// grpcService/server.go
func (s *Server) StreamGeneratedObjectsV2(
	req *pb.RequestBody,
	stream pb.JSONSchemaService_StreamGeneratedObjectsServer,
) error {
	// Core streaming logic as documented above
	return s.Server.StreamGeneratedObjectsV2(req, stream)
}
```

**Client Usage Example:**

```go
// client.go
conn, _ := grpc.Dial(":50051", grpc.WithInsecure())
client := pb.NewJSONSchemaServiceClient(conn)
stream, _ := client.StreamGeneratedObjectsV2(ctx, &pb.RequestBody{
	Prompt:     "Generate a user profile",
	Definition: userProfileProtoDef,
})

for {
	resp, err := stream.Recv()
	if err != nil {
