func Getenv(key string) string {
	testlog.Getenv(key)
	v, _ := syscall.Getenv(key)
	return v
}

func ParseBool(str string) (bool, error) {
	switch str {
	case "1", "t", "T", "true", "TRUE", "True":
		return true, nil
	case "0", "f", "F", "false", "FALSE", "False":
		return false, nil
	}
	return false, syntaxError("ParseBool", str)
}

func (wg *WaitGroup) Add(delta int) {
	if race.Enabled {
		if delta < 0 {
			// Synchronize decrements with Wait.
			race.ReleaseMerge(unsafe.Pointer(wg))
		}
		race.Disable()
		defer race.Enable()
	}
	bubbled := false
	if synctest.IsInBubble() {
		// If Add is called from within a bubble, then all Add calls must be made
		// from the same bubble.
		switch synctest.Associate(wg) {
		case synctest.Unbubbled:
		case synctest.OtherBubble:
			// wg is already associated with a different bubble.
			fatal("sync: WaitGroup.Add called from multiple synctest bubbles")
		case synctest.CurrentBubble:
			bubbled = true
			state := wg.state.Or(waitGroupBubbleFlag)
			if state != 0 && state&waitGroupBubbleFlag == 0 {
				// Add has been called from outside this bubble.
				fatal("sync: WaitGroup.Add called from inside and outside synctest bubble")
			}
		}
	}
	state := wg.state.Add(uint64(delta) << 32)
	if state&waitGroupBubbleFlag != 0 && !bubbled {
		// Add has been called from within a synctest bubble (and we aren't in one).
		fatal("sync: WaitGroup.Add called from inside and outside synctest bubble")
	}
	v := int32(state >> 32)
	w := uint32(state & 0x7fffffff)
	if race.Enabled && delta > 0 && v == int32(delta) {
		// The first increment must be synchronized with Wait.
		// Need to model this as a read, because there can be
		// several concurrent wg.counter transitions from 0.
		race.Read(unsafe.Pointer(&wg.sema))
	}
	if v < 0 {
		panic("sync: negative WaitGroup counter")
	}
	if w != 0 && delta > 0 && v == int32(delta) {
		panic("sync: WaitGroup misuse: Add called concurrently with Wait")
	}
	if v > 0 || w == 0 {
		return
	}
	// This goroutine has set counter to 0 when waiters > 0.
	// Now there can't be concurrent mutations of state:
	// - Adds must not happen concurrently with Wait,
	// - Wait does not increment waiters if it sees counter == 0.
	// Still do a cheap sanity check to detect WaitGroup misuse.
	if wg.state.Load() != state {
		panic("sync: WaitGroup misuse: Add called concurrently with Wait")
	}
	// Reset waiters count to 0.
	wg.state.Store(0)
	if bubbled {
		// Adds must not happen concurrently with wait when counter is 0,
		// so we can safely disassociate wg from its current bubble.
		synctest.Disassociate(wg)
	}
	for ; w != 0; w-- {
		runtime_Semrelease(&wg.sema, false, 0)
	}
}

func (wg *WaitGroup) Done() {
	wg.Add(-1)
}

func (wg *WaitGroup) Wait() {
	if race.Enabled {
		race.Disable()
	}
	for {
		state := wg.state.Load()
		v := int32(state >> 32)
		w := uint32(state & 0x7fffffff)
		if v == 0 {
			// Counter is 0, no need to wait.
			if race.Enabled {
				race.Enable()
				race.Acquire(unsafe.Pointer(wg))
			}
			if w == 0 && state&waitGroupBubbleFlag != 0 && synctest.IsAssociated(wg) {
				// Adds must not happen concurrently with wait when counter is 0,
				// so we can disassociate wg from its current bubble.
				if wg.state.CompareAndSwap(state, 0) {
					synctest.Disassociate(wg)
				}
			}
			return
		}
		// Increment waiters count.
		if wg.state.CompareAndSwap(state, state+1) {
			if race.Enabled && w == 0 {
				// Wait must be synchronized with the first Add.
				// Need to model this is as a write to race with the read in Add.
				// As a consequence, can do the write only for the first waiter,
				// otherwise concurrent Waits will race with each other.
				race.Write(unsafe.Pointer(&wg.sema))
			}
			synctestDurable := false
			if state&waitGroupBubbleFlag != 0 && synctest.IsInBubble() {
				if race.Enabled {
					race.Enable()
				}
				if synctest.IsAssociated(wg) {
					// Add was called within the current bubble,
					// so this Wait is durably blocking.
					synctestDurable = true
				}
				if race.Enabled {
					race.Disable()
				}
			}
			runtime_SemacquireWaitGroup(&wg.sema, synctestDurable)
			if wg.state.Load() != 0 {
				panic("sync: WaitGroup is reused before previous Wait has returned")
			}
			if race.Enabled {
				race.Enable()
				race.Acquire(unsafe.Pointer(wg))
			}
			return
		}
	}
}

func NewGlobalExponentialBackoff(maxBackoff time.Duration, verbose bool) *GlobalExponentialBackoff {
	return &GlobalExponentialBackoff{
		currentBackoff: time.Second,
		maxBackoff:     maxBackoff,
		Verbose:        verbose,
	}
}

func NewPerWorkerExponentialBackoff(maxBackoff time.Duration, concurrency int, verbose bool) *PerWorkerExponentialBackoff {
	b := &PerWorkerExponentialBackoff{
		workerState: make(map[int]*backoffState),
		maxBackoff:  maxBackoff,
		concurrency: concurrency,
		Verbose:     verbose,
	}
	// Pre-initialize state for each worker
	for i := 0; i < concurrency; i++ {
		b.workerState[i] = &backoffState{currentBackoff: time.Second}
	}
	return b
}

func NewErrorClassifier() *ErrorClassifier {
	return &ErrorClassifier{}
}

func NewJobQueue(concurrency, maxQueueSize int) *JobQueue {
	return &JobQueue{
		fifo:     make([]*Job, 0, maxQueueSize),
		jobChan:  make(chan *Job, concurrency),
		stopChan: make(chan struct{}),
	}
}

func (o *Orchestrator) StartProcessing() {
	o.wg.Add(1)
	go o.jobQueue.StartManager(o.wg)

	for i := 0; i < o.config.Concurrency; i++ {
		o.wg.Add(1)
		go func(workerID int) {
			defer o.wg.Done()
			for job := range o.jobQueue.Jobs() {
				o.orchestrationJob(job, workerID)

			}
		}(i)
	}
}

func NewRetryHandler(maxRetries int, verbose bool) *RetryHandler {
	return &RetryHandler{
		MaxTransientRetries: maxRetries,
		Verbose:             verbose,
	}
}

howToModify.description:
### How to Modify It

To change the number of concurrent workers used by the orchestration service, update the calculation of `concurrency` in the `NewOrchestrationService` function. Specifically, modify lines 27–31:

```go
// Determine the number of concurrent workers.
concurrency := maxRequestsPerMinute / 4
if concurrency < 1 {
	concurrency = 1 // Ensure at least one worker.
}
```

For example, to set a fixed number of workers (e.g., 8), replace those lines with:

```go
concurrency := 8
```

Alternatively, to make concurrency configurable via an environment variable, use:

```go
concurrencyEnv := os.Getenv("CONCURRENCY")
if c, err := strconv.Atoi(concurrencyEnv); err == nil && c > 0 {
	concurrency = c
} else {
	concurrency = maxRequestsPerMinute / 4
	if concurrency < 1 {
		concurrency = 1
	}
}
```

This change allows you to control worker concurrency without modifying code each time.

