func Printf(format string, v ...any) {
	std.output(0, 2, func(b []byte) []byte {
		return fmt.Appendf(b, format, v...)
	})
}

func (m *Mutex) Lock() {
	m.mu.Lock()
}

func (m *Mutex) Unlock() {
	m.mu.Unlock()
}

func (t Time) Before(u Time) bool {
	if t.wall&u.wall&hasMonotonic != 0 {
		return t.ext < u.ext
	}
	ts := t.sec()
	us := u.sec()
	return ts < us || ts == us && t.nsec() < u.nsec()
}

func (d Duration) Round(m Duration) Duration {
	if m <= 0 {
		return d
	}
	r := d % m
	if d < 0 {
		r = -r
		if lessThanHalf(r, m) {
			return d + r
		}
		if d1 := d - m + r; d1 < d {
			return d1
		}
		return minDuration // overflow
	}
	if lessThanHalf(r, m) {
		return d - r
	}
	if d1 := d + m - r; d1 > d {
		return d1
	}
	return maxDuration // overflow
}

func (t Time) Add(d Duration) Time {
	dsec := int64(d / 1e9)
	nsec := t.nsec() + int32(d%1e9)
	if nsec >= 1e9 {
		dsec++
		nsec -= 1e9
	} else if nsec < 0 {
		dsec--
		nsec += 1e9
	}
	t.wall = t.wall&^nsecMask | uint64(nsec) // update nsec
	t.addSec(dsec)
	if t.wall&hasMonotonic != 0 {
		te := t.ext + int64(d)
		if d < 0 && te > t.ext || d > 0 && te < t.ext {
			// Monotonic clock reading now out of range; degrade to wall-only.
			t.stripMono()
		} else {
			t.ext = te
		}
	}
	return t
}

func Until(t Time) Duration {
	if t.wall&hasMonotonic != 0 && !runtimeIsBubbled() {
		// Common case optimization: if t has monotonic time, then Sub will use only it.
		return subMono(t.ext, runtimeNano()-startNano)
	}
	return t.Sub(Now())
}

func Now() Time {
	sec, nsec, mono := runtimeNow()
	if mono == 0 {
		return Time{uint64(nsec), sec + unixToInternal, Local}
	}
	mono -= startNano
	sec += unixToInternal - minWall
	if uint64(sec)>>33 != 0 {
		// Seconds field overflowed the 33 bits available when
		// storing a monotonic time. This will be true after
		// March 16, 2157.
		return Time{uint64(nsec), sec + minWall, Local}
	}
	return Time{hasMonotonic | uint64(sec)<<nsecShift | uint64(nsec), mono, Local}
}

howItsUsed.description:
### How It's Used

```go
// main.go
package main

import (
	"time"
	"backoff"
)

func main() {
	// Example using NoBackoff
	noBackoff := &backoff.NoBackoff{Verbose: true}
	workerID := 1
	noBackoff.ActivateBackoff(workerID, 0) // Will log and sleep for ~200ms + jitter

	// Example using GlobalExponentialBackoff
	maxBackoff := 5 * time.Second
	globalBackoff := backoff.NewGlobalExponentialBackoff(maxBackoff, true)

	// Simulate a rate limit hit
	globalBackoff.ActivateBackoff(workerID, 0) // Activates global backoff

	// Worker applies backoff before retrying
	globalBackoff.ApplyBackoff(workerID)

	// Reset backoff after successful operation
	globalBackoff.ResetBackoff(workerID)
}
```

### How It's Used

Suppose you have an HTTP API endpoint that processes requests to an external service with rate limits. To handle rate limiting gracefully, you can integrate the `GlobalExponentialBackoff` strategy from the `backoff` package into your handler logic. This ensures that when a rate limit is hit, all workers pause before retrying, reducing the chance of overwhelming the external service.

```go
// main.go
package main

import (
	"net/http"
	"time"
	"myapp/backoff"
)

var globalBackoff = backoff.NewGlobalExponentialBackoff(8*time.Second, true)

func externalAPICall(workerID int) error {
	// Simulate a rate-limited call
	if shouldRateLimit() {
		globalBackoff.ActivateBackoff(workerID, 0)
		return ErrRateLimited
	}
	// ... actual API call logic ...
	return nil
}

func handler(w http.ResponseWriter, r *http.Request) {
	workerID := getWorkerID(r)
	globalBackoff.ApplyBackoff(workerID)

	err := externalAPICall(workerID)
	if err == ErrRateLimited {
		http.Error(w, "Rate limit hit, please retry later.", http.StatusTooManyRequests)
		return
	}

	w.WriteHeader(http.StatusOK)
	w.Write([]byte("Success"))
}

func main() {
	http.HandleFunc("/process", handler)
	http.ListenAndServe(":8080", nil)
}
```

**Flow of Data:**
1. Each incoming request triggers `handler`.
2. Before making the external API call, `globalBackoff.ApplyBackoff(workerID)` checks if a global backoff is active and sleeps if necessary.
3. If the API call hits a rate limit, `globalBackoff.ActivateBackoff(workerID, 0)` sets a new backoff period for all workers.
4. The handler responds with an appropriate HTTP status, depending on the outcome.

This integration ensures coordinated backoff across all workers, improving reliability and compliance with external rate limits.

howToBreak.description:
### How to Break It

The code uses mutexes to synchronize access to shared state in the `GlobalExponentialBackoff` strategy, aiming to prevent race conditions. However, subtle bugs can still be introduced if the locking discipline is violated or if state is accessed outside the protected critical section. For example, in `ApplyBackoff`, the code locks the mutex, reads `backoffUntil`, unlocks, and then sleeps if needed. If another goroutine modifies `backoffUntil` between unlock and sleep, the worker may sleep for an outdated duration, leading to inconsistent backoff behavior.

A specific modification that introduces a subtle race condition is to move the sleep operation inside the locked section in `ApplyBackoff`:

```go
// BAD: Sleep while holding the lock
func (b *GlobalExponentialBackoff) ApplyBackoff(workerID int) {
    b.mu.Lock()
    sleepDuration := time.Until(b.backoffUntil)
    if sleepDuration > 0 {
        if b.Verbose {
            log.Printf("Global backoff active. Worker %d pausing for %v.", workerID, sleepDuration.Round(time.Millisecond))
        }
        time.Sleep(sleepDuration) // Holding lock during sleep
    }
    b.mu.Unlock()
}
```

This change causes all workers to block on the mutex while one is sleeping, serializing their execution and defeating the purpose of concurrency. It can also lead to deadlocks if other methods (like `ActivateBackoff` or `ResetBackoff`) are called from other goroutines and need the same lock. This subtle bug is hard to detect in testing but can severely degrade performance and reliability in production.

howItsUsed.description:
### How It's Used

The backoff strategies in this package are commonly integrated into distributed systems that require robust rate-limiting and retry mechanisms. For example, in a Kafka consumer group, each worker processing messages from a partition can use `GlobalExponentialBackoff` to coordinate retries when the broker signals a rate limit or temporary failure. This ensures that all workers back off together, preventing thundering herd problems and reducing load on the broker.

In a dependency injection scenario, the backoff strategy can be registered as a singleton service. Components that interact with external APIs or databases resolve the backoff instance from the container and invoke its methods during error handling. This centralizes backoff logic and makes it configurable at the application level.

For high-performance workloads, such as a goroutine pool managing thousands of concurrent tasks, the backoff strategies help manage resource contention. When a shared resource (like a cache or database) returns a rate limit error, the pool controller calls `ActivateBackoff` on the global strategy, causing all goroutines to pause for an exponentially increasing duration. This prevents resource exhaustion and allows the system to recover gracefully.

#### Example: Kafka Consumer Integration

```go
// Go
type Consumer struct {
    backoff *backoff.GlobalExponentialBackoff
}

func (c *Consumer) ProcessMessage(msg Message, workerID int) {
    for {
        err := c.handle(msg)
        if err == ErrRateLimited {
            c.backoff.ActivateBackoff(workerID, 0)
            c.backoff.ApplyBackoff(workerID)
            continue
        }
        break
    }
}
```

#### Example: Dependency Injection

```go
// Go
