func Errorf(format string, a ...any) error {
	p := newPrinter()
	p.wrapErrs = true
	p.doPrintf(format, a)
	s := string(p.buf)
	var err error
	switch len(p.wrappedErrs) {
	case 0:
		err = errors.New(s)
	case 1:
		w := &wrapError{msg: s}
		w.err, _ = a[p.wrappedErrs[0]].(error)
		err = w
	default:
		if p.reordered {
			slices.Sort(p.wrappedErrs)
		}
		var errs []error
		for i, argNum := range p.wrappedErrs {
			if i > 0 && p.wrappedErrs[i-1] == argNum {
				continue
			}
			if e, ok := a[argNum].(error); ok {
				errs = append(errs, e)
			}
		}
		err = &wrapErrors{s, errs}
	}
	p.free()
	return err
}

func Getenv(key string) string {
	testlog.Getenv(key)
	v, _ := syscall.Getenv(key)
	return v
}

func ToLower(s string) string {
	isASCII, hasUpper := true, false
	for i := 0; i < len(s); i++ {
		c := s[i]
		if c >= utf8.RuneSelf {
			isASCII = false
			break
		}
		hasUpper = hasUpper || ('A' <= c && c <= 'Z')
	}

	if isASCII { // optimize for ASCII-only strings.
		if !hasUpper {
			return s
		}
		var (
			b   Builder
			pos int
		)
		b.Grow(len(s))
		for i := 0; i < len(s); i++ {
			c := s[i]
			if 'A' <= c && c <= 'Z' {
				c += 'a' - 'A'
				if pos < i {
					b.WriteString(s[pos:i])
				}
				b.WriteByte(c)
				pos = i + 1
			}
		}
		if pos < len(s) {
			b.WriteString(s[pos:])
		}
		return b.String()
	}
	return Map(unicode.ToLower, s)
}

func NewStandardClient() *http.Client {
		once.Do(func() {
			standardClient = &http.Client{}
	})
	return standardClient
}

func NewGenericGzipClient(baseClient *http.Client) *http.Client {
	// Create a new client that will have our custom transport.
	newClient := &http.Client{}
	var transport http.RoundTripper

	if baseClient != nil {
		// If a base client is provided, copy its configuration.
		transport = baseClient.Transport
		newClient.CheckRedirect = baseClient.CheckRedirect
		newClient.Jar = baseClient.Jar
		newClient.Timeout = baseClient.Timeout
	}

	// If the transport is still nil (either because baseClient was nil or
	// baseClient.Transport was nil), use the default transport.
	if transport == nil {
		transport = http.DefaultTransport
	}

	// Set the new client's transport to our gzip transport, which wraps the
	// determined underlying transport.
	newClient.Transport = &gzipTransport{
		underlyingTransport: transport,
	}

	return newClient
}

func NewGeminiClientAdapter(
	apiKey string,
	builder requestManagement.RequestBuilder,
	converter modelConverter.ModelConverter,
	httpClient *http.Client,
) *GeminiClientAdapter {
	if httpClient == nil {
		httpClient = &http.Client{}
	}
	return &GeminiClientAdapter{
		httpClient:     httpClient,
		apiKey:         apiKey,
		baseURL:        "https://generativelanguage.googleapis.com/v1beta",
		requestBuilder: builder,
		modelConverter: converter,
	}
}

func NewLocalClientAdapter(
	url, token string,
	builder requestManagement.RequestBuilder,
	converter requestManagement.RequestConverter,
	httpClient *http.Client,
) *LocalClientAdapter {
	return &LocalClientAdapter{
		client:           httpClient,
		requestBuilder:   builder,
		requestConverter: converter,
		targetURL:        url,
		authToken:        token,
	}
}

func NewOpenAIClientAdapter(
	apiKey string,
	builder requestManagement.RequestBuilder,
) *OpenAIClientAdapter {
	client := openai.NewClient(apiKey)
	return &OpenAIClientAdapter{
		client:         client,
		requestBuilder: builder,
	}
}

func NewModelConverter() ModelConverter {
	return &providerModelConverter{}
}

func NewDefaultOpenAIReqBuilder(modelConverter modelConverter.ModelConverter) RequestBuilder {
