func (s *Server) Serve(lis net.Listener) error {
	s.mu.Lock()
	s.printf("serving")
	s.serve = true
	if s.lis == nil {
		// Serve called after Stop or GracefulStop.
		s.mu.Unlock()
		lis.Close()
		return ErrServerStopped
	}

	s.serveWG.Add(1)
	defer func() {
		s.serveWG.Done()
		if s.quit.HasFired() {
			// Stop or GracefulStop called; block until done and return nil.
			<-s.done.Done()
		}
	}()

	ls := &listenSocket{
		Listener: lis,
		channelz: channelz.RegisterSocket(&channelz.Socket{
			SocketType:    channelz.SocketTypeListen,
			Parent:        s.channelz,
			RefName:       lis.Addr().String(),
			LocalAddr:     lis.Addr(),
			SocketOptions: channelz.GetSocketOption(lis)},
		),
	}
	s.lis[ls] = true

	defer func() {
		s.mu.Lock()
		if s.lis != nil && s.lis[ls] {
			ls.Close()
			delete(s.lis, ls)
		}
		s.mu.Unlock()
	}()

	s.mu.Unlock()
	channelz.Info(logger, ls.channelz, "ListenSocket created")

	var tempDelay time.Duration // how long to sleep on accept failure
	for {
		rawConn, err := lis.Accept()
		if err != nil {
			if ne, ok := err.(interface {
				Temporary() bool
			}); ok && ne.Temporary() {
				if tempDelay == 0 {
					tempDelay = 5 * time.Millisecond
				} else {
					tempDelay *= 2
				}
				if max := 1 * time.Second; tempDelay > max {
					tempDelay = max
				}
				s.mu.Lock()
				s.printf("Accept error: %v; retrying in %v", err, tempDelay)
				s.mu.Unlock()
				timer := time.NewTimer(tempDelay)
				select {
				case <-timer.C:
				case <-s.quit.Done():
					timer.Stop()
					return nil
				}
				continue
			}
			s.mu.Lock()
			s.printf("done serving; Accept = %v", err)
			s.mu.Unlock()

			if s.quit.HasFired() {
				return nil
			}
			return err
		}
		tempDelay = 0
		// Start a new goroutine to deal with rawConn so we don't stall this Accept
		// loop goroutine.
		//
		// Make sure we account for the goroutine so GracefulStop doesn't nil out
		// s.conns before this conn can be added.
		s.serveWG.Add(1)
		go func() {
			s.handleRawConn(lis.Addr().String(), rawConn)
			s.serveWG.Done()
		}()
	}
}

func NewGRPCServer() *grpc.Server {

	// Load the TLS certificate and key
	certFile := os.Getenv("CERT_FILE")
	keyFile := os.Getenv("KEY_FILE")

	grpcServer := &grpc.Server{}
	if os.Getenv("GRPC_UNSECURE") != "true" {
		if certFile == "" || keyFile == "" {
			log.Println("CERT_FILE and KEY_FILE environment variables must be set")
			return nil
		}

		cert, err := tls.LoadX509KeyPair(certFile, keyFile)
		if err != nil {
			log.Fatalf("Failed to load key pair: %v", err)
		}

		// Create a certificate pool and add the server certificate
		creds := credentials.NewTLS(&tls.Config{
			Certificates: []tls.Certificate{cert},
			MinVersion:   tls.VersionTLS12,
		})

		grpcServer = grpc.NewServer(
			grpc.UnaryInterceptor(AuthInterceptor),
			grpc.Creds(creds),
		)
	} else {
		grpcServer = grpc.NewServer(
			grpc.UnaryInterceptor(AuthInterceptor),
		)
	}

	// Register your service implementation with the gRPC server
	pb.RegisterJSONSchemaServiceServer(grpcServer, &Server{})
	// Enable gRPC reflection
	reflection.Register(grpcServer)

	return grpcServer
}

func NewHTTPManager(l net.Listener, r chan bool) *HTTPManager {
	return &HTTPManager{
		listener: l,
		server: &http.Server{
			Handler:           service.NewHttpServer().Router,
			ReadHeaderTimeout: 5 * time.Second,
		},
		ready: r,
	}
}

func (hm *HTTPManager) Start() error {
	hm.ready <- true
	return hm.server.Serve(hm.listener)
}

howItsUsed.description:
### How It's Used

Here’s a simple example of how to use the server startup logic from another part of your application, such as in a `main.go` file. This demonstrates the necessary imports, variable setup, and function calls:

```go
package main

import (
	"os"
	"objectweaver/grpcService"
	"objectweaver/httpManager"
)

func main() {
	// Handle panics gracefully
	defer handlePanic()

	// Channels to signal readiness
	httpReady := make(chan bool)
	grpcReady := make(chan bool)

	// Start both servers concurrently
	go startServers(httpReady, grpcReady)

	// Wait until both servers are ready
	<-httpReady
	<-grpcReady

	// Print branding and info
	printAscii()

	// Keep the main process running
	select {}
}
```

**Usage Notes:**
- Ensure environment variables like `PORT`, `CERT_FILE`, and `KEY_FILE` are set as needed.
- The `startServers` function will initialize both HTTP and gRPC servers on the same port using connection multiplexing.
- The `printAscii()` function displays branding and license information after both servers are ready.
- The main goroutine blocks indefinitely to keep the servers running.

### How It's Used

Below is an example of how the core server management code is integrated into a larger application, specifically as the entrypoint for a service that exposes both HTTP and gRPC endpoints on the same port. This pattern is common in microservices architectures where both REST and gRPC APIs are needed.

```go
// main.go

func main() {
	// Setup panic handling and logging
	defer handlePanic()

	// Channels to signal readiness of HTTP and gRPC servers
	httpReady := make(chan bool)
	grpcReady := make(chan bool)

	// Start both servers concurrently
	go startServers(httpReady, grpcReady)

	// Wait until both servers are ready before proceeding
	<-httpReady
	<-grpcReady

	// Print branding and license info once servers are up
	printAscii()

	// Block forever to keep the service running
	select {}
}
```

The `startServers` function is responsible for initializing a TCP listener, using `cmux` to multiplex HTTP and gRPC traffic, and starting both servers:

```go
func startServers(httpReady, grpcReady chan bool) {
	port := os.Getenv("PORT")
	if port == "" {
		port = defaultPort
	}
	lis, err := net.Listen("tcp", ":"+port)
	if err != nil {
		log.Fatalf("Failed to listen on port %s: %v", port, err)
	}
	m := cmux.New(lis)
	grpcL := m.Match(cmux.HTTP2())
	httpL := m.Match(cmux.HTTP1Fast())

	grpcM := NewGRPCManager(grpcL, grpcReady)
	httpM := NewHTTPManager(httpL, httpReady)

	go func() {
		if err := grpcM.Start(); err != nil {
			log.Fatalf("gRPC server failed: %v", err)
		}
	}()
	go func() {
		if err := httpM.Start(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("HTTP server failed: %v", err)
		}
	}()
	if err := m.Serve(); err != nil {
		log.Fatalf("cmux server failed: %v", err)
	}
}
```

**Flow of Data:**
- The main function launches both servers and waits for readiness signals.
- `startServers` sets up a TCP listener and uses `cmux` to route HTTP/1.x and HTTP/2 (gRPC) traffic to their respective handlers.
- Each manager (`GRPCManager`, `HTTPManager`) starts its server and signals readiness via channels.
- Once both servers are running, the application prints branding info and blocks, keeping the service alive.

This structure allows the application to serve both HTTP and gRPC APIs efficiently on a single port, with clear separation of concerns and robust error handling.

### How It's Used

The server management code is designed for integration into a robust, multi-protocol microservices architecture. A common usage scenario is within a containerized environment (e.g., Kubernetes), where the service must handle both HTTP and gRPC traffic efficiently on a single port. This is achieved using the `cmux` library, which multiplexes connections and routes them to the appropriate protocol handler.

For example, in a message-driven system using Kafka, the service might consume events and trigger business logic exposed via gRPC endpoints. The HTTP endpoints could serve RESTful APIs for web clients or expose health checks for orchestration tools. Dependency injection containers (like Uber's `fx` or Google's `wire`) can instantiate and manage the lifecycle of `GRPCManager` and `HTTPManager`, ensuring clean startup and shutdown sequences.

In high-performance scenarios, such as real-time data processing, the server leverages goroutines to concurrently handle incoming connections. The readiness channels (`httpReady`, `grpcReady`) allow orchestration scripts or health probes to verify when each protocol handler is available, supporting zero-downtime deployments and rolling updates.

**Example Integration:**

```go
// main.go
func main() {
    // Dependency injection setup (pseudo-code)
    container := NewContainer()
    container.Provide(NewGRPCManager)
    container.Provide(NewHTTPManager)
    container.Invoke(func(grpcM ServerManager, httpM ServerManager) {
        go grpcM.Start()
        go httpM.Start()
    })

    // Kafka consumer triggers gRPC calls
    go func() {
        for msg := range kafkaConsumer.Messages() {
            grpcClient.ProcessEvent(msg)
        }
    }()

    // Health checks via HTTP
    httpClient.Get("http://localhost:2008/health")
}
```

This pattern ensures the service is scalable, maintainable, and ready for integration into modern cloud-native infrastructures.

