func NewReader(r io.Reader) (*Reader, error) {
	z := new(Reader)
	if err := z.Reset(r); err != nil {
		return nil, err
	}
	return z, nil
}

func FileServer(root FileSystem) Handler {
	return &fileHandler{root}
}

func (h Header) Get(key string) string {
	return textproto.MIMEHeader(h).Get(key)
}

func (h Header) Del(key string) {
	textproto.MIMEHeader(h).Del(key)
}

func Error(w ResponseWriter, error string, code int) {
	h := w.Header()

	// Delete the Content-Length header, which might be for some other content.
	// Assuming the error string fits in the writer's buffer, we'll figure
	// out the correct Content-Length for it later.
	//
	// We don't delete Content-Encoding, because some middleware sets
	// Content-Encoding: gzip and wraps the ResponseWriter to compress on-the-fly.
	// See https://go.dev/issue/66343.
	h.Del("Content-Length")

	// There might be content type already set, but we reset it to
	// text/plain for the error message.
	h.Set("Content-Type", "text/plain; charset=utf-8")
	h.Set("X-Content-Type-Options", "nosniff")
	w.WriteHeader(code)
	fmt.Fprintln(w, error)
}

func StripPrefix(prefix string, h Handler) Handler {
	if prefix == "" {
		return h
	}
	return HandlerFunc(func(w ResponseWriter, r *Request) {
		p := strings.TrimPrefix(r.URL.Path, prefix)
		rp := strings.TrimPrefix(r.URL.RawPath, prefix)
		if len(p) < len(r.URL.Path) && (r.URL.RawPath == "" || len(rp) < len(r.URL.RawPath)) {
			r2 := new(Request)
			*r2 = *r
			r2.URL = new(url.URL)
			*r2.URL = *r.URL
			r2.URL.Path = p
			r2.URL.RawPath = rp
			h.ServeHTTP(w, r2)
		} else {
			NotFound(w, r)
		}
	})
}

func Getenv(key string) string {
	testlog.Getenv(key)
	v, _ := syscall.Getenv(key)
	return v
}

func NewRouter() *Mux {
	return NewMux()
}

func Compress(level int, types ...string) func(next http.Handler) http.Handler {
	compressor := NewCompressor(level, types...)
	return compressor.Handler
}

func Logger(next http.Handler) http.Handler {
	return DefaultLogger(next)
}

func RealIP(h http.Handler) http.Handler {
	fn := func(w http.ResponseWriter, r *http.Request) {
		if rip := realIP(r); rip != "" {
			r.RemoteAddr = rip
		}
		h.ServeHTTP(w, r)
	}

	return http.HandlerFunc(fn)
}

func Recoverer(next http.Handler) http.Handler {
	fn := func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if rvr := recover(); rvr != nil {
				if rvr == http.ErrAbortHandler {
					// we don't recover http.ErrAbortHandler so the response
					// to the client is aborted, this should not be logged
					panic(rvr)
				}

				logEntry := GetLogEntry(r)
				if logEntry != nil {
					logEntry.Panic(rvr, debug.Stack())
				} else {
					PrintPrettyStack(rvr)
				}

				if r.Header.Get("Connection") != "Upgrade" {
					w.WriteHeader(http.StatusInternalServerError)
				}
			}
		}()

		next.ServeHTTP(w, r)
	}

	return http.HandlerFunc(fn)
}

func RequestID(next http.Handler) http.Handler {
	fn := func(w http.ResponseWriter, r *http.Request) {
		ctx := r.Context()
		requestID := r.Header.Get(RequestIDHeader)
		if requestID == "" {
			myid := atomic.AddUint64(&reqid, 1)
			requestID = fmt.Sprintf("%s-%06d", prefix, myid)
		}
		ctx = context.WithValue(ctx, RequestIDKey, requestID)
		next.ServeHTTP(w, r.WithContext(ctx))
	}
	return http.HandlerFunc(fn)
}

func ThrottleBacklog(limit, backlogLimit int, backlogTimeout time.Duration) func(http.Handler) http.Handler {
	return ThrottleWithOpts(ThrottleOpts{Limit: limit, BacklogLimit: backlogLimit, BacklogTimeout: backlogTimeout})
}

func Timeout(timeout time.Duration) func(next http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		fn := func(w http.ResponseWriter, r *http.Request) {
			ctx, cancel := context.WithTimeout(r.Context(), timeout)
			defer func() {
				cancel()
				if ctx.Err() == context.DeadlineExceeded {
					w.WriteHeader(http.StatusGatewayTimeout)
				}
			}()

			r = r.WithContext(ctx)
			next.ServeHTTP(w, r)
		}
		return http.HandlerFunc(fn)
	}
}

func URLFormat(next http.Handler) http.Handler {
	fn := func(w http.ResponseWriter, r *http.Request) {
		ctx := r.Context()

		var format string
		path := r.URL.Path

		rctx := chi.RouteContext(r.Context())
		if rctx != nil && rctx.RoutePath != "" {
			path = rctx.RoutePath
		}

		if strings.Index(path, ".") > 0 {
			base := strings.LastIndex(path, "/")
			idx := strings.LastIndex(path[base:], ".")

			if idx > 0 {
				idx += base
				format = path[idx+1:]

				if rctx != nil {
					rctx.RoutePath = path[:idx]
				}
			}
		}

		r = r.WithContext(context.WithValue(ctx, URLFormatCtxKey, format))

		next.ServeHTTP(w, r)
	}
	return http.HandlerFunc(fn)
}

func (mx *Mux) Use(middlewares ...func(http.Handler) http.Handler) {
	if mx.handler != nil {
		panic("chi: all middlewares must be defined before routes on a mux")
	}
	mx.middlewares = append(mx.middlewares, middlewares...)
}

func (mx *Mux) Handle(pattern string, handler http.Handler) {
	if i := strings.IndexAny(pattern, " \t"); i >= 0 {
		method, rest := pattern[:i], strings.TrimLeft(pattern[i+1:], " \t")
		mx.Method(method, rest, handler)
		return
	}

	mx.handle(mALL, pattern, handler)
}

func (mx *Mux) Get(pattern string, handlerFn http.HandlerFunc) {
	mx.handle(mGET, pattern, handlerFn)
}

func (mx *Mux) Group(fn func(r Router)) Router {
	im := mx.With()
	if fn != nil {
		fn(im)
	}
	return im
}

func Handler(options Options) func(next http.Handler) http.Handler {
	c := New(options)
	return c.Handler
}

func ValidatePassword(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {

		if os.Getenv("ENVIRONMENT") == "development" {
			// In development mode, skip password validation
			next.ServeHTTP(w, r)
			return
		}

		// Extract the Authorization header
		authHeader := r.Header.Get("Authorization")
		if authHeader == "" {
			log.Println("No Authorization header found")
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Check if it is a Bearer token
		if !strings.HasPrefix(authHeader, "Bearer ") {
			log.Println("Invalid token")
			log.Println("auth header: ", authHeader)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Extract the token value
		token := strings.TrimPrefix(authHeader, "Bearer ")

		// Get the PASSWORD environment variable
		envPassword := os.Getenv("PASSWORD")
		if envPassword == "" {
			log.Println("Missing environment variable PASSWORD")
			http.Error(w, "Server error: PASSWORD environment variable not set", http.StatusInternalServerError)
			return
		}

		// Compare the token with the PASSWORD environment variable
		if token != envPassword {
			log.Println("The token does not match")
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// If everything is OK, proceed to the next handler
		next.ServeHTTP(w, r)
	})
}

func ObjectGen(w http.ResponseWriter, r *http.Request) {
	// Ensure method is POST
	if r.Method != http.MethodPost {
		http.Error(w, "Only POST method is allowed", http.StatusMethodNotAllowed)
		return
	}

	if os.Getenv("ENVIRONMENT") == "development" {
		log.Printf("Request received: %s %s", r.Method, r.URL.Path)
	}

	// Check if context is already cancelled before doing any work
	if r.Context().Err() != nil {
		log.Printf("Request context already cancelled at entry: %v", r.Context().Err())
		// Depending on which middleware cancelled it, a response might have been sent.
		// It's often safer to just return here if you expect a middleware to handle the response.
		// If you are sure no response has been sent, you could write one, e.g.:
		// switch r.Context().Err() {
		// case context.Canceled:
		// 	http.Error(w, "Request cancelled by client", http.StatusClientClosedRequest)
		// case context.DeadlineExceeded:
		// 	http.Error(w, "Request timed out", http.StatusRequestTimeout)
		// default:
		// 	http.Error(w, "Request context error", http.StatusInternalServerError)
		// }
		return
	}

	// Parse the request body
	body := &client.RequestBody{}
	decoder := json.NewDecoder(r.Body)
	if err := decoder.Decode(&body); err != nil {
		log.Printf("Error decoding request body: %v", err)
		// Check context before writing, in case of timeout during body read/decode.
		if r.Context().Err() == nil {
			http.Error(w, "Invalid request body", http.StatusBadRequest)
		}
		return
	}
	defer r.Body.Close()

	// Check for circular definitions
	if checks.CheckCircularDefinitions(body.Definition) {
		if r.Context().Err() == nil {
			http.Error(w, "Circular object definition", http.StatusUnprocessableEntity)
		}
		return
	}

	// Create factory
	factory := factory.NewGeneratorFactory(&factory.GeneratorConfig{
		Mode:           factory.ModeParallel,
		MaxConcurrency: 10,
	})

	// Create generator
	generator, err := factory.Create()
	if err != nil {
		log.Printf("Error creating generator: %v", err)
		if r.Context().Err() == nil {
			http.Error(w, "Failed to create generator: "+err.Error(), http.StatusInternalServerError)
		}
		return
	}

	// Generate
	request := domain.NewGenerationRequest(body.Prompt, body.Definition)
	result, err := generator.Generate(request)
	if err != nil {
		log.Printf("Error during generation: %v", err)
		if r.Context().Err() == nil {
			http.Error(w, "Generation failed: "+err.Error(), http.StatusInternalServerError)
		}
		return
	}

	data := result.Data()
	cost := result.Metadata().Cost

	// Log the result data for debugging
	log.Printf("[ObjectGen] Result data: %+v", data)
	log.Printf("[ObjectGen] Result cost: %f", cost)
	log.Printf("[ObjectGen] Result metadata: %+v", result.Metadata())

	// Marshal and send the successful response
	response := Response{
		Data:    data,
		UsdCost: cost,
	}

	// Log the final JSON response being sent to client
	if responseJSON, err := json.Marshal(response); err == nil {
		log.Printf("[ObjectGen] Final response JSON: %s", string(responseJSON))
	}

	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(response); err != nil {
		// This error might occur if the client disconnected or if (less likely by now)
		// another component wrote a response.
		log.Printf("Error encoding response (context error: %v): %v", r.Context().Err(), err)
		// Don't try http.Error here as headers might have been partially written.
	}
}

func ServeIndexHTML(w http.ResponseWriter, r *http.Request) {
	// Define the file path to index.html
	filePath := "/static/index.html"

	// Read the HTML file content
	fileContent, err := os.ReadFile(filePath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	// Define environment variables
	authToken := os.Getenv("PASSWORD")

	// Create a template with environment variables
	tmpl, err := template.New("index").Parse(string(fileContent))
	if err != nil {
		http.Error(w, "Error parsing template", http.StatusInternalServerError)
		return
	}

	// Define the data to pass to the template
	data := struct {
		AuthToken string
	}{
		AuthToken: authToken,
	}

	// Execute the template with the data
	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		http.Error(w, "Error executing template", http.StatusInternalServerError)
		return
	}

	// Set the Content-Type header and write the response
	w.Header().Set("Content-Type", "text/html")
	_, err = w.Write(buf.Bytes())
	if err != nil {
		http.Error(w, "Error writing response", http.StatusInternalServerError)
		return
	}
}

func PrometheusMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		activeRequests.Inc()
		defer activeRequests.Dec()

		requestSize, _ := strconv.Atoi(r.Header.Get("Content-Length"))

		rw := &responseWriter{ResponseWriter: w, StatusCode: http.StatusOK}
		next.ServeHTTP(rw, r)

		duration := time.Since(start).Seconds()

		statusCode := rw.StatusCode
		if statusCode >= 400 {
			errorRequestsTotal.WithLabelValues(r.Method, r.URL.Path, http.StatusText(statusCode)).Inc()
		}

		httpRequestsTotal.WithLabelValues(r.Method, r.URL.Path, http.StatusText(statusCode)).Inc()
		httpRequestDuration.WithLabelValues(r.Method, r.URL.Path).Observe(duration)
		httpResponseSize.WithLabelValues(r.Method, r.URL.Path).Observe(float64(rw.Size))
		httpRequestSize.WithLabelValues(r.Method, r.URL.Path).Observe(float64(requestSize))
	})
}

howItsUsed.description:
### How It's Used

Here’s a simple example showing how to use the `NewHttpServer` function to create and start the HTTP server in a Go application. This demonstrates the necessary imports, variable setup, and how to serve requests using the configured router.

```go
// main.go
package main

import (
	"log"
	"net/http"
	"objectweaver/service"
)

func main() {
	// Create a new HTTP server with all middleware and routes mounted
	server := service.NewHttpServer()

	// Start serving HTTP requests on port 8080
	log.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", server.Router); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}
```

This code sets up the server, mounts all handlers and middleware, and starts listening for incoming requests. The server will handle API requests, serve static files (in development), and apply all configured middleware automatically.

### How It's Used

The `Server` struct and its middleware configuration are typically integrated into a scalable web service architecture, such as a microservice behind an API gateway or within a containerized environment orchestrated by Kubernetes. Below is an example of how this code fits into a dependency injection container and interacts with a message queue system for high-performance object generation:

```go
// main.go
package main

import (
	"objectweaver/service"
	"objectweaver/queue"
)

func main() {
	// Dependency injection: register the HTTP server and queue consumer
	container := NewContainer()
	container.Register("httpServer", service.NewHttpServer())
	container.Register("objectGenConsumer", queue.NewConsumer(
		topic: "objectGenRequests",
		handler: func(msg queue.Message) {
			// Deserialize and process the message using the same logic as ObjectGen
			// This enables horizontal scaling and async processing
			service.HandleObjectGenMessage(msg)
		},
	))

	// Start HTTP server and queue consumer concurrently
	go func() {
		httpServer := container.Resolve("httpServer").(*service.Server)
		http.ListenAndServe(":8080", httpServer.Router)
	}()
	go func() {
		consumer := container.Resolve("objectGenConsumer").(*queue.Consumer)
		consumer.Start()
	}()

	select {} // Block forever
}
```

In this architecture:

- The HTTP server is initialized with all middleware for security, observability, and resource management.
- The `ObjectGen` handler can be invoked via HTTP or asynchronously via a message queue (e.g., Kafka, NATS), supporting both synchronous API requests and background batch processing.
- Middleware such as throttling, timeouts, and gzip decompression ensure robust handling of high-throughput scenarios.
- Metrics are collected via Prometheus middleware for monitoring and autoscaling.
- The dependency injection container manages lifecycle and dependencies, enabling easy testing and modularity.

This pattern supports high availability, scalability, and maintainability in production-grade systems.

