func Unmarshal(data []byte, v any) error {
	// Check for well-formedness.
	// Avoids filling out half a data structure
	// before discovering a JSON syntax error.
	var d decodeState
	err := checkValid(data, &d.scan)
	if err != nil {
		return err
	}

	d.init(data)
	return d.unmarshal(v)
}

func Marshal(v any) ([]byte, error) {
	e := newEncodeState()
	defer encodeStatePool.Put(e)

	err := e.marshal(v, encOpts{escapeHTML: true})
	if err != nil {
		return nil, err
	}
	buf := append([]byte(nil), e.Bytes()...)

	return buf, nil
}

func MarshalIndent(v any, prefix, indent string) ([]byte, error) {
	b, err := Marshal(v)
	if err != nil {
		return nil, err
	}
	b2 := make([]byte, 0, indentGrowthFactor*len(b))
	b2, err = appendIndent(b2, b, prefix, indent)
	if err != nil {
		return nil, err
	}
	return b2, nil
}

func NewDecoder(r io.Reader) *Decoder {
	return &Decoder{r: r}
}

func (dec *Decoder) Decode(v any) error {
	if dec.err != nil {
		return dec.err
	}

	if err := dec.tokenPrepareForDecode(); err != nil {
		return err
	}

	if !dec.tokenValueAllowed() {
		return &SyntaxError{msg: "not at beginning of value", Offset: dec.InputOffset()}
	}

	// Read whole value into buffer.
	n, err := dec.readValue()
	if err != nil {
		return err
	}
	dec.d.init(dec.buf[dec.scanp : dec.scanp+n])
	dec.scanp += n

	// Don't save err from unmarshal into dec.err:
	// the connection is still usable since we read a complete JSON
	// object from it before the error happened.
	err = dec.d.unmarshal(v)

	// fixup token streaming state
	dec.tokenValueEnd()

	return err
}

func NewEncoder(w io.Writer) *Encoder {
	return &Encoder{w: w, escapeHTML: true}
}

func (enc *Encoder) Encode(v any) error {
	if enc.err != nil {
		return enc.err
	}

	e := newEncodeState()
	defer encodeStatePool.Put(e)

	err := e.marshal(v, encOpts{escapeHTML: enc.escapeHTML})
	if err != nil {
		return err
	}

	// Terminate each value with a newline.
	// This makes the output look a little nicer
	// when debugging, and some kind of space
	// is required if the encoded value was a number,
	// so that the reader knows there aren't more
	// digits coming.
	e.WriteByte('\n')

	b := e.Bytes()
	if enc.indentPrefix != "" || enc.indentValue != "" {
		enc.indentBuf, err = appendIndent(enc.indentBuf[:0], b, enc.indentPrefix, enc.indentValue)
		if err != nil {
			return err
		}
		b = enc.indentBuf
	}
	if _, err = enc.w.Write(b); err != nil {
		enc.err = err
	}
	return err
}

func Println(a ...any) (n int, err error) {
	return Fprintln(os.Stdout, a...)
}

func Printf(format string, v ...any) {
	std.output(0, 2, func(b []byte) []byte {
		return fmt.Appendf(b, format, v...)
	})
}

func (h Header) Set(key, value string) {
	textproto.MIMEHeader(h).Set(key, value)
}

func (r *Request) Context() context.Context {
	if r.ctx != nil {
		return r.ctx
	}
	return context.Background()
}

func Error(w ResponseWriter, error string, code int) {
	h := w.Header()

	// Delete the Content-Length header, which might be for some other content.
	// Assuming the error string fits in the writer's buffer, we'll figure
	// out the correct Content-Length for it later.
	//
	// We don't delete Content-Encoding, because some middleware sets
	// Content-Encoding: gzip and wraps the ResponseWriter to compress on-the-fly.
	// See https://go.dev/issue/66343.
	h.Del("Content-Length")

	// There might be content type already set, but we reset it to
	// text/plain for the error message.
	h.Set("Content-Type", "text/plain; charset=utf-8")
	h.Set("X-Content-Type-Options", "nosniff")
	w.WriteHeader(code)
	fmt.Fprintln(w, error)
}

func Getenv(key string) string {
	testlog.Getenv(key)
	v, _ := syscall.Getenv(key)
	return v
}

func CheckCircularDefinitions(def *jsonSchema.Definition) bool {
	visited := make(map[*jsonSchema.Definition]bool)
	recStack := make(map[*jsonSchema.Definition]bool)

	var dfs func(*jsonSchema.Definition) bool
	dfs = func(d *jsonSchema.Definition) bool {
		if d == nil {
			return false
		}
		// If the node is in the recursion stack, we found a cycle
		if recStack[d] {
			return true
		}
		// If the node is already visited and not part of the recursion stack
		if visited[d] {
			return false
		}

		// Mark the current node as visited and part of the recursion stack
		visited[d] = true
		recStack[d] = true

		// Recurse for all properties
		for _, prop := range d.Properties {
			if dfs(&prop) {
				return true
			}
		}

		// Recurse for items if present
		if d.Items != nil {
			if dfs(d.Items) {
				return true
			}
		}

		// Remove the node from the recursion stack
		recStack[d] = false
		return false
	}

	return dfs(def)
}

func NewGenerationRequest(prompt string, schema *jsonSchema.Definition) *GenerationRequest {
	return &GenerationRequest{
		prompt:      prompt,
		schema:      schema,
		context:     context.Background(),
		metadata:    make(map[string]interface{}),
		constraints: DefaultConstraints(),
	}
}

func (r *GenerationResult) Data() map[string]interface{} {
	return r.data
}

func (r *GenerationResult) Metadata() *ResultMetadata {
	return r.metadata
}

func NewGeneratorFactory(config *GeneratorConfig) *GeneratorFactory {
	if config == nil {
		config = DefaultGeneratorConfig()
	}
	return &GeneratorFactory{config: config}
}

func (f *GeneratorFactory) Create() (domain.Generator, error) {
	// Create core components
	analyzer := f.createAnalyzer()
	executor := f.createExecutor()
	assembler := f.createAssembler()
	strategy := f.createStrategy()

	// Create generator based on mode
	var generator domain.Generator

	switch f.config.Mode {
	case ModeStreamingProgressive:
		generator = application.NewProgressiveGenerator(analyzer, executor, assembler.(domain.ProgressiveAssembler), strategy)
	case ModeStreaming, ModeStreamingComplete:
		generator = application.NewStreamingGenerator(analyzer, executor, assembler.(domain.StreamingAssembler), strategy)
	default:
		generator = application.NewDefaultGenerator(analyzer, executor, assembler, strategy)
	}

	// Register plugins if needed
	if pluggable, ok := generator.(PluginRegistry); ok {
		f.registerPlugins(pluggable)
	}

	return generator, nil
}

